"use client";

import * as React from "react";
import { useState, useEffect } from "react";
import { PageHeader } from "@/components/admin/ui/page-header";
import { AdminButton } from "@/components/admin/ui/admin-button";
import { Split, BarChart3, Plus } from "lucide-react";
import { ExperimentCard } from "@/components/ab-testing/experiment-card";
import { CreateExperimentDialog } from "@/components/ab-testing/create-experiment-dialog";
import { StatsCards } from "@/components/ab-testing/stats-cards";
import { FiltersBar } from "@/components/ab-testing/filters-bar";
import { EmptyState } from "@/components/ab-testing/empty-state";
import { abTestingService } from "@/services/ab-testing-service";
import { Experiment, CreateExperimentData } from "@/types/ab-testing";

export default function ABTestingPage() {
  const [experiments, setExperiments] = useState<Experiment[]>([]);
  const [filteredExperiments, setFilteredExperiments] = useState<Experiment[]>([]);
  const [statusFilter, setStatusFilter] = useState<string>("all");
  const [searchTerm, setSearchTerm] = useState<string>("");
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [showCreateDialog, setShowCreateDialog] = useState<boolean>(false);

  // Load experiments on mount
  useEffect(() => {
    loadExperiments();
  }, []);

  // Apply filters whenever experiments, status filter, or search term changes
  useEffect(() => {
    let result = experiments;

    if (statusFilter !== "all") {
      result = result.filter(exp => exp.status === statusFilter);
    }

    if (searchTerm) {
      const term = searchTerm.toLowerCase();
      result = result.filter(exp => 
        exp.title.toLowerCase().includes(term) || 
        exp.description.toLowerCase().includes(term) ||
        exp.createdBy.toLowerCase().includes(term)
      );
    }

    setFilteredExperiments(result);
  }, [experiments, statusFilter, searchTerm]);

  const loadExperiments = async () => {
    try {
      setLoading(true);
      const data = await abTestingService.getAllExperiments();
      setExperiments(data);
      setError(null);
    } catch (err) {
      console.error("Error loading experiments:", err);
      setError("فشل تحميل تجارب A/B");
    } finally {
      setLoading(false);
    }
  };

  const handleCreateExperiment = async (newExpData: CreateExperimentData) => {
    try {
      const newExp = await abTestingService.createExperiment(newExpData);

      setExperiments(prev => [newExp, ...prev]);
    } catch (err) {
      console.error("Error creating experiment:", err);
      alert("فشل إنشاء تجربة جديدة");
    }
  };

  const toggleExperimentStatus = async (id: string, newStatus: "active" | "paused" | "completed") => {
    try {
      const updatedExp = await abTestingService.updateExperimentStatus(id, newStatus);
      setExperiments(prev => 
        prev.map(exp => 
          exp.id === id ? updatedExp : exp
        )
      );
    } catch (err) {
      console.error("Error updating experiment status:", err);
      alert("فشل تحديث حالة التجربة");
    }
  };

  const declareWinner = async (id: string, winner: "A" | "B") => {
    try {
      const updatedExp = await abTestingService.declareWinner(id, winner);
      setExperiments(prev => 
        prev.map(exp => 
          exp.id === id ? updatedExp : exp
        )
      );
    } catch (err) {
      console.error("Error declaring winner:", err);
      alert("فشل إعلان الفائز");
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto"></div>
          <p className="mt-4 text-lg font-medium">جاري تحميل تجارب A/B...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="text-center p-6 max-w-md">
          <div className="mx-auto bg-destructive/20 dark:bg-destructive/10 w-16 h-16 rounded-full flex items-center justify-center">
            <Split className="w-8 h-8 text-destructive" />
          </div>
          <h3 className="text-xl font-bold mt-4">خطأ في تحميل البيانات</h3>
          <p className="text-muted-foreground mt-2">{error}</p>
          <AdminButton 
            className="mt-6"
            onClick={loadExperiments}
          >
            إعادة المحاولة
          </AdminButton>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 pb-10">
      <PageHeader
        title="مختبر النمو وتجارب (A/B Testing)"
        description="قارن بين نسختين من الاختبارات أو الدروس، واعرف أيهما يحقق أفضل تفاعل (Engagement) وأعلى معدلات استيعاب لدى المحاربين."
      >
        <CreateExperimentDialog onCreate={handleCreateExperiment}>
          <AdminButton icon={Plus} className="h-12 rounded-xl text-lg font-bold gap-2 bg-gradient-to-r from-teal-500 to-emerald-600 hover:from-teal-600 hover:to-emerald-700 shadow-[0_0_20px_rgba(20,184,166,0.3)]">
            إنشاء تجربة انقسام جديدة
          </AdminButton>
        </CreateExperimentDialog>
      </PageHeader>

      <StatsCards experiments={experiments} />

      <FiltersBar 
        searchTerm={searchTerm}
        statusFilter={statusFilter}
        onSearchChange={setSearchTerm}
        onStatusChange={setStatusFilter}
        experimentCount={filteredExperiments.length}
      />

      <h3 className="text-xl font-black flex items-center gap-2 mt-12 mb-6">
        <BarChart3 className="w-6 h-6 text-primary" />
        لوحة المختبر (Active & Past Experiments)
      </h3>

      {filteredExperiments.length === 0 ? (
        <EmptyState onCreateClick={() => setShowCreateDialog(true)} />
      ) : (
        <div className="space-y-8">
          {filteredExperiments.map((exp, idx) => (
            <ExperimentCard 
              key={exp.id}
              experiment={exp}
              onToggleStatus={toggleExperimentStatus}
              onDeclareWinner={declareWinner}
            />
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

import * as React from "react";
import { useQuery } from "@tanstack/react-query";
import { ColumnDef } from "@tanstack/react-table";
import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { Bookmark, Pencil, Plus, RefreshCw, Trash2 } from "lucide-react";
import { toast } from "sonner";
import { PageHeader } from "@/components/admin/ui/page-header";
import { AdminButton } from "@/components/admin/ui/admin-button";
import { AdminCard } from "@/components/admin/ui/admin-card";
import { AdminDataTable, RowActions } from "@/components/admin/ui/admin-table";
import { ConfirmDialog } from "@/components/admin/ui/confirm-dialog";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";

interface CourseCategory {
  id: string;
  name: string;
  slug: string;
  icon: string | null;
  description: string | null;
  coursesCount: number;
  createdAt: string;
}

const categorySchema = z.object({
  name: z.string().min(1, "اسم التصنيف مطلوب"),
  slug: z.string().optional().nullable(),
  icon: z.string().optional().nullable(),
  description: z.string().optional().nullable(),
});

type CategoryFormValues = z.infer<typeof categorySchema>;

const defaultValues: CategoryFormValues = {
  name: "",
  slug: "",
  icon: "",
  description: "",
};

export default function AdminCourseCategoriesPage() {
  const [dialogOpen, setDialogOpen] = React.useState(false);
  const [editingCategory, setEditingCategory] = React.useState<CourseCategory | null>(null);
  const [deleteDialog, setDeleteDialog] = React.useState<{ open: boolean; id: string | null }>({
    open: false,
    id: null,
  });

  const { data: categories = [], isLoading, refetch } = useQuery({
    queryKey: ["admin", "course-categories", "page"],
    queryFn: async () => {
      const response = await fetch("/api/admin/course-categories");
      const result = await response.json();
      return (result.data?.categories || []) as CourseCategory[];
    },
  });

  const form = useForm<CategoryFormValues>({
    resolver: zodResolver(categorySchema),
    defaultValues,
  });

  const openDialog = (category?: CourseCategory) => {
    if (category) {
      setEditingCategory(category);
      form.reset({
        name: category.name,
        slug: category.slug || "",
        icon: category.icon || "",
        description: category.description || "",
      });
    } else {
      setEditingCategory(null);
      form.reset(defaultValues);
    }

    setDialogOpen(true);
  };

  const handleSubmit = async (values: CategoryFormValues) => {
    try {
      const method = editingCategory ? "PATCH" : "POST";
      const payload = editingCategory ? { ...values, id: editingCategory.id } : values;
      const response = await fetch("/api/admin/course-categories", {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      const result = await response.json();

      if (!response.ok) {
        toast.error(result?.error || result?.message || "تعذر حفظ التصنيف");
        return;
      }

      toast.success(editingCategory ? "تم تحديث التصنيف بنجاح" : "تم إنشاء التصنيف بنجاح");
      setDialogOpen(false);
      setEditingCategory(null);
      form.reset(defaultValues);
      await refetch();
    } catch {
      toast.error("حدث خطأ أثناء الاتصال بالخادم");
    }
  };

  const handleDelete = async () => {
    if (!deleteDialog.id) return;

    try {
      const response = await fetch("/api/admin/course-categories", {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: deleteDialog.id }),
      });
      const result = await response.json();

      if (!response.ok) {
        toast.error(result?.error || result?.message || "تعذر حذف التصنيف");
        return;
      }

      toast.success("تم حذف التصنيف بنجاح");
      await refetch();
    } catch {
      toast.error("حدث خطأ أثناء الاتصال بالخادم");
    } finally {
      setDeleteDialog({ open: false, id: null });
    }
  };

  const columns: ColumnDef<CourseCategory>[] = [
    {
      accessorKey: "name",
      header: "التصنيف",
      cell: ({ row }) => (
        <div className="space-y-1">
          <p className="font-bold">{row.original.name}</p>
          <p className="text-xs text-muted-foreground">{row.original.slug}</p>
        </div>
      ),
    },
    {
      accessorKey: "icon",
      header: "الأيقونة",
      cell: ({ row }) => (
        <Badge variant="outline" className="rounded-full px-2.5 py-0.5 text-[11px] font-bold">
          {row.original.icon || "BookOpen"}
        </Badge>
      ),
    },
    {
      accessorKey: "coursesCount",
      header: "الدورات",
      cell: ({ row }) => <span className="font-bold">{row.original.coursesCount}</span>,
    },
    {
      accessorKey: "description",
      header: "الوصف",
      cell: ({ row }) => (
        <p className="max-w-md truncate text-sm text-muted-foreground">
          {row.original.description || "لا يوجد وصف"}
        </p>
      ),
    },
    {
      id: "actions",
      header: "إجراءات",
      cell: ({ row }) => (
        <RowActions
          row={row.original}
          onView={openDialog}
          onEdit={openDialog}
          onDelete={(category) => setDeleteDialog({ open: true, id: category.id })}
        />
      ),
    },
  ];

  return (
    <div className="space-y-8 pb-20" dir="rtl">
      <PageHeader
        title="تصنيفات الدورات"
        description="إدارة التصنيفات المستخدمة لتنظيم الدورات التعليمية داخل المنصة."
        badge={`${categories.length} تصنيف`}
      >
        <div className="flex flex-wrap items-center gap-2">
          <AdminButton variant="outline" icon={RefreshCw} onClick={() => refetch()}>
            تحديث
          </AdminButton>
          <AdminButton icon={Plus} onClick={() => openDialog()}>
            تصنيف جديد
          </AdminButton>
        </div>
      </PageHeader>

      <div className="grid gap-4 md:grid-cols-3">
        <AdminCard className="space-y-3 p-5">
          <div className="flex items-center justify-between">
            <span className="text-xs font-bold text-muted-foreground">إجمالي التصنيفات</span>
            <Bookmark className="h-4 w-4 text-primary" />
          </div>
          <p className="text-3xl font-black">{categories.length}</p>
        </AdminCard>
        <AdminCard className="space-y-3 p-5">
          <div className="flex items-center justify-between">
            <span className="text-xs font-bold text-muted-foreground">الدورات المرتبطة</span>
            <Bookmark className="h-4 w-4 text-cyan-600" />
          </div>
          <p className="text-3xl font-black">
            {categories.reduce((total, category) => total + category.coursesCount, 0)}
          </p>
        </AdminCard>
        <AdminCard className="space-y-3 p-5">
          <div className="flex items-center justify-between">
            <span className="text-xs font-bold text-muted-foreground">تصنيفات نشطة</span>
            <Bookmark className="h-4 w-4 text-emerald-600" />
          </div>
          <p className="text-3xl font-black">
            {categories.filter((category) => category.coursesCount > 0).length}
          </p>
        </AdminCard>
      </div>

      <AdminDataTable
        columns={columns}
        data={categories}
        loading={isLoading}
        emptyMessage={{
          title: "لا توجد تصنيفات بعد",
          description: "ابدأ بإضافة تصنيف جديد لتنظيم الدورات التعليمية.",
        }}
      />

      <Dialog
        open={dialogOpen}
        onOpenChange={(open) => {
          setDialogOpen(open);
          if (!open) {
            setEditingCategory(null);
            form.reset(defaultValues);
          }
        }}
      >
        <DialogContent className="max-w-2xl rounded-[2rem] p-0">
          <div className="p-6 sm:p-8" dir="rtl">
            <DialogHeader className="space-y-2 text-right">
              <DialogTitle className="text-2xl font-black">
                {editingCategory ? "تعديل تصنيف دورة" : "إضافة تصنيف دورة"}
              </DialogTitle>
            </DialogHeader>

            <Form {...form}>
              <form onSubmit={form.handleSubmit(handleSubmit)} className="mt-6 space-y-5">
                <div className="grid gap-4 sm:grid-cols-2">
                  <FormField
                    control={form.control}
                    name="name"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>اسم التصنيف</FormLabel>
                        <FormControl>
                          <Input {...field} value={field.value || ""} placeholder="مثال: الأحياء" />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={form.control}
                    name="slug"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>الرابط المختصر</FormLabel>
                        <FormControl>
                          <Input {...field} value={field.value || ""} placeholder="biology-courses" />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>

                <FormField
                  control={form.control}
                  name="icon"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>اسم الأيقونة</FormLabel>
                      <FormControl>
                        <Input {...field} value={field.value || ""} placeholder="BookOpen" />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="description"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>الوصف</FormLabel>
                      <FormControl>
                        <Textarea
                          {...field}
                          value={field.value || ""}
                          className="min-h-[110px]"
                          placeholder="وصف مختصر للتصنيف."
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <DialogFooter className="gap-2 sm:justify-start">
                  <AdminButton type="submit" icon={editingCategory ? Pencil : Plus}>
                    {editingCategory ? "حفظ التعديلات" : "إنشاء التصنيف"}
                  </AdminButton>
                  <AdminButton type="button" variant="outline" onClick={() => setDialogOpen(false)}>
                    إلغاء
                  </AdminButton>
                </DialogFooter>
              </form>
            </Form>
          </div>
        </DialogContent>
      </Dialog>

      <ConfirmDialog
        open={deleteDialog.open}
        onOpenChange={(open) => setDeleteDialog({ open, id: open ? deleteDialog.id : null })}
        onConfirm={handleDelete}
        title="حذف التصنيف"
        description="سيتم حذف التصنيف نهائيًا إذا لم يكن مرتبطًا بأي دورة تعليمية."
        confirmText="حذف التصنيف"
        variant="destructive"
      />
    </div>
  );
}

"use client";

import * as React from "react";
import { useParams, useRouter } from "next/navigation";
import { PageHeader } from "@/components/admin/ui/page-header";
import { AdminCard } from "@/components/admin/ui/admin-card";
import { AdminButton } from "@/components/admin/ui/admin-button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Progress } from "@/components/ui/progress";
import { 
  Users, 
  Clock, 
  PlayCircle, 
  GraduationCap, 
  BarChart3, 
  MessageCircle, 
  Award,
  Eye,
  TrendingUp,
  Calendar,
  DollarSign,
  Star,
  BookOpen,
  ExternalLink,
  Edit,
  Trash2
} from "lucide-react";
import { useQuery } from "@tanstack/react-query";
import { toast } from "sonner";
import { ConfirmDialog } from "@/components/admin/ui/confirm-dialog";

interface Course {
  id: string;
  name: string;
  nameAr: string | null;
  code: string | null;
  description: string | null;
  price: number;
  level: string;
  instructorName: string | null;
  instructorId: string | null;
  categoryId: string | null;
  thumbnailUrl: string | null;
  trailerUrl: string | null;
  isActive: boolean;
  isPublished: boolean;
  durationHours: number;
  requirements: string | null;
  learningObjectives: string | null;
  _count: {
    enrollments: number;
    topics: number;
    reviews: number;
  };
  rating: number;
  enrolledCount: number;
  createdAt: string;
  updatedAt: string;
}

interface CourseStats {
  totalLessons: number;
  totalDuration: number;
  avgRating: number;
  reviewCount: number;
  enrollmentCount: number;
}

export default function CourseDetailsPage() {
  const router = useRouter();
  const params = useParams();
  const courseId = params.id as string;

  const [deleteDialog, setDeleteDialog] = React.useState<{ open: boolean; id: string | null }>({
    open: false,
    id: null,
  });

  const { data: course, isLoading, refetch } = useQuery({
    queryKey: ["admin", "course", courseId],
    queryFn: async () => {
      const response = await fetch(`/api/admin/courses/${courseId}`);
      const result = await response.json();
      return result.data?.course as Course;
    },
  });

  const { data: stats } = useQuery({
    queryKey: ["admin", "course-stats", courseId],
    queryFn: async () => {
      const response = await fetch(`/api/admin/courses/${courseId}/stats`);
      const result = await response.json();
      return result.data?.stats as CourseStats;
    },
    enabled: !!course,
  });

  const handleDelete = async () => {
    if (!deleteDialog.id) return;
    try {
      const response = await fetch("/api/admin/courses", {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: deleteDialog.id }),
      });

      if (response.ok) {
        toast.success("تم حذف الدورة بنجاح");
        router.push("/admin/courses");
      } else {
        toast.error("فشل في حذف الدورة");
      }
    } catch (_error) {
      toast.error("خطأ في الاتصال");
    } finally {
      setDeleteDialog({ open: false, id: null });
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
      </div>
    );
  }

  if (!course) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-center">
        <BarChart3 className="h-16 w-16 text-muted-foreground mb-4" />
        <h3 className="text-xl font-bold text-muted-foreground">الدورة غير موجودة</h3>
        <p className="text-muted-foreground mt-2">يرجى التحقق من المعرف المدخل والمحاولة مرة أخرى</p>
      </div>
    );
  }

  const colors: Record<string, string> = {
    EASY: "bg-emerald-500/10 text-emerald-500 border-emerald-500/20",
    MEDIUM: "bg-blue-500/10 text-blue-500 border-blue-500/20",
    HARD: "bg-orange-500/10 text-orange-500 border-orange-500/20",
    EXPERT: "bg-rose-500/10 text-rose-500 border-rose-500/20",
  };
  const labels: Record<string, string> = { EASY: "مبتدئ", MEDIUM: "متوسط", HARD: "متقدم", EXPERT: "خبير" };
  const level = (course.level || "MEDIUM") as string;

  return (
    <div className="space-y-8 pb-10" dir="rtl">
      <PageHeader
        title={course.nameAr || course.name}
        description="إدارة تفاصيل الدورة، المحتوى، والطلاب المسجلين."
      >
        <div className="flex gap-3">
          <AdminButton 
            icon={ExternalLink} 
            variant="outline"
            onClick={() => window.open(`/courses/${course.id}`, '_blank')}
          >
            عرض في الموقع
          </AdminButton>
          <AdminButton 
            icon={Edit} 
            onClick={() => router.push(`/admin/courses/${course.id}/edit`)}
          >
            تعديل
          </AdminButton>
          <AdminButton 
            icon={Trash2} 
            variant="destructive"
            onClick={() => setDeleteDialog({ open: true, id: course.id })}
          >
            حذف
          </AdminButton>
        </div>
      </PageHeader>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <AdminCard className="p-6">
            <div className="flex flex-col md:flex-row gap-6">
              <div className="relative h-48 w-full md:w-64 flex-shrink-0">
                {course.thumbnailUrl ? (
                  <img 
                    src={course.thumbnailUrl} 
                    alt={course.name} 
                    className="h-full w-full rounded-2xl object-cover"
                  />
                ) : (
                  <div className="h-full w-full rounded-2xl bg-gradient-to-br from-blue-500/20 to-indigo-500/20 flex items-center justify-center">
                    <PlayCircle className="h-12 w-12 text-primary" />
                  </div>
                )}
              </div>

              <div className="flex-1">
                <div className="flex flex-wrap items-start gap-3 mb-3">
                  <Badge className={`rounded-full px-3 py-0.5 font-bold text-[10px] ${colors[level] || colors.MEDIUM}`}>
                    {labels[level] || level}
                  </Badge>
                  <Badge variant={course.isPublished ? "default" : "outline"} className={`rounded-full px-3 py-0.5 text-[10px] font-bold ${course.isPublished ? "bg-emerald-500/10 text-emerald-500 border-emerald-500/20" : "text-muted-foreground opacity-50 font-normal"}`}>
                    {course.isPublished ? "منشور" : "مسودة"}
                  </Badge>
                  <Badge variant={course.isActive ? "default" : "secondary"} className="rounded-full px-3 py-0.5 font-bold text-[10px]">
