              </AdminCard>
            </TabsContent>

            <TabsContent value="objectives" className="mt-4">
              <AdminCard className="p-6">
                <h3 className="font-black text-lg mb-3">أهداف التعلم</h3>
                <ul className="list-disc list-inside text-muted-foreground space-y-2">
                  {(course.learningObjectives || "لا توجد أهداف محددة").split("\n").map((obj, idx) => (
                    obj.trim() && <li key={idx}>{obj}</li>
                  ))}
                </ul>
              </AdminCard>
            </TabsContent>

            <TabsContent value="requirements" className="mt-4">
              <AdminCard className="p-6">
                <h3 className="font-black text-lg mb-3">المتطلبات</h3>
                <ul className="list-disc list-inside text-muted-foreground space-y-2">
                  {(course.requirements || "لا توجد متطلبات محددة").split("\n").map((req, idx) => (
                    req.trim() && <li key={idx}>{req}</li>
                  ))}
                </ul>
              </AdminCard>
            </TabsContent>
          </Tabs>
        </div>

        <div className="space-y-6">
          <AdminCard className="p-6">
            <h3 className="font-black text-lg mb-4">إحصائيات الدورة</h3>

            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Users className="w-4 h-4 text-muted-foreground" />
                  <span className="text-sm text-muted-foreground">المسجلين</span>
                </div>
                <span className="font-bold">{course._count.enrollments}</span>
              </div>

              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <PlayCircle className="w-4 h-4 text-muted-foreground" />
                  <span className="text-sm text-muted-foreground">الوحدات</span>
                </div>
                <span className="font-bold">{course._count.topics}</span>
              </div>

              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Star className="w-4 h-4 text-muted-foreground" />
                  <span className="text-sm text-muted-foreground">التقييم</span>
                </div>
                <div className="flex items-center gap-1">
                  <span className="font-bold">{course.rating?.toFixed(1) || "0.0"}</span>
                  <Star className="w-3 h-3 fill-yellow-500 text-yellow-500" />
                </div>
              </div>

              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <MessageCircle className="w-4 h-4 text-muted-foreground" />
                  <span className="text-sm text-muted-foreground">التقييمات</span>
                </div>
                <span className="font-bold">{course._count.reviews}</span>
              </div>

              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Clock className="w-4 h-4 text-muted-foreground" />
                  <span className="text-sm text-muted-foreground">المدة</span>
                </div>
                <span className="font-bold">{course.durationHours} ساعة</span>
              </div>
            </div>

            <div className="mt-6 pt-4 border-t">
              <h4 className="font-bold mb-3">مستوى الصعوبة</h4>
              <div className="flex flex-col gap-2">
                {(['EASY', 'MEDIUM', 'HARD', 'EXPERT'] as const).map((lvl) => (
                  <div key={lvl} className="flex items-center justify-between">
                    <span className={`text-sm ${lvl === level ? 'font-bold' : 'text-muted-foreground'}`}>
                      {labels[lvl]}
                    </span>
                    <div className="w-20 h-2 bg-muted rounded-full overflow-hidden">
                      <div 
                        className={`h-full ${
                          lvl === level 
                            ? (lvl === 'EASY' ? 'bg-emerald-500' : 
                               lvl === 'MEDIUM' ? 'bg-blue-500' : 
                               lvl === 'HARD' ? 'bg-orange-500' : 'bg-rose-500')
                            : 'bg-transparent'
                        }`}
                        style={{ width: lvl === level ? '100%' : '0%' }}
                      ></div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </AdminCard>

          <AdminCard className="p-6">
            <h3 className="font-black text-lg mb-4">السعر</h3>
            <div className="flex items-baseline gap-2">
              <span className="text-3xl font-black">{course.price}</span>
              <span className="text-muted-foreground">EGP</span>
            </div>
          </AdminCard>

          <AdminCard className="p-6">
            <h3 className="font-black text-lg mb-4">الإحصائيات المتقدمة</h3>
            <div className="space-y-4">
              <div>
                <div className="flex justify-between mb-1">
                  <span className="text-sm text-muted-foreground">معدل الإكمال</span>
                  <span className="text-sm font-bold">65%</span>
                </div>
                <Progress value={65} className="h-2" />
              </div>

              <div>
                <div className="flex justify-between mb-1">
                  <span className="text-sm text-muted-foreground">معدل الإعجاب</span>
                  <span className="text-sm font-bold">82%</span>
                </div>
                <Progress value={82} className="h-2" />
              </div>

              <div>
                <div className="flex justify-between mb-1">
                  <span className="text-sm text-muted-foreground">متوسط الوقت</span>
                  <span className="text-sm font-bold">2.4h/week</span>
                </div>
              </div>
            </div>
          </AdminCard>
        </div>
      </div>

      <ConfirmDialog
        open={deleteDialog.open}
        onOpenChange={(open) => setDeleteDialog({ open, id: null })}
        onConfirm={handleDelete}
        title="حذف الدورة؟"
        description={`هل أنت متأكد أنك تريد حذف "${course.nameAr}"؟ لا يمكن التراجع عن هذا الإجراء.`}
      />
    </div>
  );
}

"use client";

import * as React from "react";
import { useRouter } from "next/navigation";
import { useQuery } from "@tanstack/react-query";
import { ColumnDef } from "@tanstack/react-table";
import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import { z } from "zod";
import {
  Award,
  BookOpen,
  Clock,
  DollarSign,
  ExternalLink,
  Filter,
  GraduationCap,
  LayoutGrid,
  Pencil,
  PlayCircle,
  Plus,
  RefreshCw,
  Search,
  Sparkles,
  Tags,
  Trash2,
  Users,
} from "lucide-react";
import { toast } from "sonner";
import { PageHeader } from "@/components/admin/ui/page-header";
import { AdminButton } from "@/components/admin/ui/admin-button";
import { AdminCard } from "@/components/admin/ui/admin-card";
import { AdminUpload } from "@/components/admin/ui/admin-upload";
import { AdminDataTable, RowActions } from "@/components/admin/ui/admin-table";
import { ConfirmDialog } from "@/components/admin/ui/confirm-dialog";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { Badge } from "@/components/ui/badge";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

interface Course {
  id: string;
  name: string;
  nameAr: string | null;
  code: string | null;
  description: string | null;
  price: number;
  level: string;
  instructorName: string | null;
  instructorId: string | null;
  categoryId: string | null;
  thumbnailUrl: string | null;
  trailerUrl: string | null;
  isActive: boolean;
  isPublished: boolean;
  durationHours: number;
  requirements: string | null;
  learningObjectives: string | null;
  _count: {
    enrollments: number;
    topics: number;
    teachers?: number;
  };
}

interface CoursesResponse {
  data: {
    courses: Course[];
    pagination: {
      page: number;
      limit: number;
      total: number;
      totalPages: number;
    };
  };
}

interface CourseCategory {
  id: string;
  name: string;
  slug: string;
  icon: string | null;
  description: string | null;
  coursesCount: number;
}

type FilterKey = "all" | "published" | "draft" | "active" | "inactive";

const categorySchema = z.object({
  name: z.string().min(1, "اسم التصنيف مطلوب"),
  slug: z.string().optional().nullable(),
  icon: z.string().optional().nullable(),
  description: z.string().optional().nullable(),
});

const courseSchema = z.object({
  name: z.string().min(1, "اسم الدورة بالإنجليزية مطلوب"),
  nameAr: z.string().min(1, "اسم الدورة بالعربية مطلوب"),
  price: z.coerce.number().min(0, "السعر يجب أن يكون صفرًا أو أكثر"),
  level: z.enum(["EASY", "MEDIUM", "HARD", "EXPERT"]),
  instructorName: z.string().optional().nullable(),
  instructorId: z.string().optional().nullable(),
  categoryId: z.string().optional().nullable(),
  description: z.string().optional().nullable(),
  isActive: z.boolean(),
  isPublished: z.boolean(),
  durationHours: z.coerce.number().min(0, "عدد الساعات يجب أن يكون صفرًا أو أكثر"),
  requirements: z.string().optional().nullable(),
  learningObjectives: z.string().optional().nullable(),
  thumbnailUrl: z.string().optional().nullable(),
  trailerUrl: z.string().optional().nullable(),
});

type CourseFormValues = z.infer<typeof courseSchema>;
type CategoryFormValues = z.infer<typeof categorySchema>;

const levelLabels: Record<string, string> = {
  EASY: "مبتدئ",
  MEDIUM: "متوسط",
  HARD: "متقدم",
  EXPERT: "خبير",
};

const levelStyles: Record<string, string> = {
  EASY: "border-emerald-500/20 bg-emerald-500/10 text-emerald-600",
  MEDIUM: "border-sky-500/20 bg-sky-500/10 text-sky-600",
  HARD: "border-amber-500/20 bg-amber-500/10 text-amber-600",
  EXPERT: "border-rose-500/20 bg-rose-500/10 text-rose-600",
};

const filterOptions: Array<{ key: FilterKey; label: string }> = [
  { key: "all", label: "كل الدورات" },
  { key: "published", label: "المنشورة" },
  { key: "draft", label: "المسودات" },
  { key: "active", label: "النشطة" },
  { key: "inactive", label: "الموقوفة" },
];

const defaultValues: CourseFormValues = {
  name: "",
  nameAr: "",
  price: 0,
  level: "MEDIUM",
  instructorName: "",
  instructorId: "",
  categoryId: "",
  description: "",
  isActive: true,
  isPublished: false,
  durationHours: 0,
  requirements: "",
  learningObjectives: "",
  thumbnailUrl: "",
  trailerUrl: "",
};

const defaultCategoryValues: CategoryFormValues = {
  name: "",
  slug: "",
  icon: "",
  description: "",
};

export default function AdminCoursesPage() {
  const router = useRouter();
  const [dialogOpen, setDialogOpen] = React.useState(false);
  const [categoryDialogOpen, setCategoryDialogOpen] = React.useState(false);
  const [editingCourse, setEditingCourse] = React.useState<Course | null>(null);
  const [editingCategory, setEditingCategory] = React.useState<CourseCategory | null>(null);
  const [deleteDialog, setDeleteDialog] = React.useState<{ open: boolean; id: string | null }>({
    open: false,
    id: null,
  });
  const [categoryDeleteDialog, setCategoryDeleteDialog] = React.useState<{ open: boolean; id: string | null }>({
    open: false,
    id: null,
  });
  const [activeFilter, setActiveFilter] = React.useState<FilterKey>("all");
  const [selectedCategoryId, setSelectedCategoryId] = React.useState<string>("all");
  const [selectedTeacherId, setSelectedTeacherId] = React.useState<string>("all");
  const [page, setPage] = React.useState(1);
  const [limit, setLimit] = React.useState(10);
  const [search, setSearch] = React.useState("");
  const deferredCategoryId = React.useDeferredValue(selectedCategoryId);
  const deferredTeacherId = React.useDeferredValue(selectedTeacherId);
  const deferredSearch = React.useDeferredValue(search);

  const { data, isLoading, refetch } = useQuery({
    queryKey: ["admin", "courses", page, limit, deferredSearch, activeFilter, deferredCategoryId, deferredTeacherId],
    queryFn: async () => {
      const params = new URLSearchParams({
        page: page.toString(),
        limit: limit.toString(),
      });

      if (deferredSearch) params.set("search", deferredSearch);
      if (activeFilter === "active") params.set("isActive", "true");
      if (activeFilter === "inactive") params.set("isActive", "false");
      if (activeFilter === "published") params.set("isPublished", "true");
      if (activeFilter === "draft") params.set("isPublished", "false");
      if (deferredCategoryId !== "all") params.set("categoryId", deferredCategoryId);
      if (deferredTeacherId !== "all") params.set("instructorId", deferredTeacherId);

      const response = await fetch(`/api/admin/courses?${params.toString()}`);
      return (await response.json()) as CoursesResponse;
    },
  });

  const courses = data?.data?.courses || [];
  const pagination = data?.data?.pagination;

  const { data: teachers = [] } = useQuery({
    queryKey: ["admin", "teachers"],
    queryFn: async () => {
      const response = await fetch("/api/admin/teachers");
      const result = await response.json();
      return (result.data?.teachers || []) as Array<{ id: string; name: string }>;
    },
  });

  const { data: categories = [], refetch: refetchCategories } = useQuery({
    queryKey: ["admin", "course-categories"],
    queryFn: async () => {
      const response = await fetch("/api/admin/course-categories");
      const result = await response.json();
      return (result.data?.categories || []) as CourseCategory[];
    },
  });

  const totalEnrollments = React.useMemo(
    () => courses.reduce((total, course) => total + (course._count?.enrollments || 0), 0),
    [courses]
  );
  const totalCurriculumUnits = React.useMemo(
    () => courses.reduce((total, course) => total + (course._count?.topics || 0), 0),
    [courses]
  );
  const totalHours = React.useMemo(
    () => courses.reduce((total, course) => total + (course.durationHours || 0), 0),
    [courses]
  );
  const publishedCoursesCount = React.useMemo(
    () => courses.filter((course) => course.isPublished).length,
    [courses]
  );
  const activeCoursesCount = React.useMemo(
    () => courses.filter((course) => course.isActive).length,
    [courses]
  );
  const averagePrice = React.useMemo(() => {
    if (!courses.length) return 0;
    const total = courses.reduce((sum, course) => sum + (course.price || 0), 0);
    return Math.round(total / courses.length);
  }, [courses]);

  const form = useForm<CourseFormValues>({
    resolver: zodResolver(courseSchema),
    defaultValues,
  });
  const categoryForm = useForm<CategoryFormValues>({
    resolver: zodResolver(categorySchema),
    defaultValues: defaultCategoryValues,
  });

  const selectedInstructorId = form.watch("instructorId");
  const previewThumbnail = form.watch("thumbnailUrl");
  const previewName = form.watch("nameAr") || form.watch("name") || "دورة جديدة";
  const previewDescription = form.watch("description") || "أضف وصفًا مختصرًا يوضح قيمة الدورة للطلاب.";
  const previewLevel = form.watch("level");
  const previewPrice = form.watch("price");
  const previewDuration = form.watch("durationHours");
  const previewPublished = form.watch("isPublished");
  const previewActive = form.watch("isActive");
  React.useEffect(() => {
    if (!selectedInstructorId) {
      form.setValue("instructorName", "");
      return;
    }

    const teacher = teachers.find((item) => item.id === selectedInstructorId);
    if (teacher) {
      form.setValue("instructorName", teacher.name);
    }
  }, [selectedInstructorId, teachers, form]);

  React.useEffect(() => {
    setPage(1);
  }, [activeFilter, deferredCategoryId, deferredTeacherId, deferredSearch]);

  const openDialog = (course?: Course) => {
    if (course) {
      setEditingCourse(course);
      form.reset({
        name: course.name,
        nameAr: course.nameAr || "",
        price: course.price || 0,
        level: (course.level as CourseFormValues["level"]) || "MEDIUM",
        instructorName: course.instructorName || "",
        instructorId: course.instructorId || "",
        categoryId: course.categoryId || "",
        description: course.description || "",
        isActive: course.isActive,
        isPublished: course.isPublished,
        durationHours: course.durationHours || 0,
        requirements: course.requirements || "",
        learningObjectives: course.learningObjectives || "",
        thumbnailUrl: course.thumbnailUrl || "",
        trailerUrl: course.trailerUrl || "",
      });
    } else {
      setEditingCourse(null);
      form.reset(defaultValues);
    }

    setDialogOpen(true);
  };

  const openCategoryDialog = (category?: CourseCategory) => {
    if (category) {
      setEditingCategory(category);
      categoryForm.reset({
        name: category.name,
        slug: category.slug || "",
        icon: category.icon || "",
        description: category.description || "",
      });
    } else {
      setEditingCategory(null);
      categoryForm.reset(defaultCategoryValues);
    }

    setCategoryDialogOpen(true);
  };

  const handleSubmit = async (values: CourseFormValues) => {
    try {
      const method = editingCourse ? "PATCH" : "POST";
      const payload = editingCourse ? { ...values, id: editingCourse.id } : values;

      const response = await fetch("/api/admin/courses", {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (!response.ok) {
        toast.error("تعذر حفظ بيانات الدورة");
        return;
      }

      toast.success(editingCourse ? "تم تحديث الدورة بنجاح" : "تم إنشاء الدورة بنجاح");
      setDialogOpen(false);
      setEditingCourse(null);
      form.reset(defaultValues);
      await refetch();
    } catch {
      toast.error("حدث خطأ أثناء الاتصال بالخادم");
    }
  };

  const handleDelete = async () => {
    if (!deleteDialog.id) return;

    try {
      const response = await fetch("/api/admin/courses", {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: deleteDialog.id }),
      });

      if (!response.ok) {
        toast.error("تعذر حذف الدورة");
        return;
      }

      toast.success("تم حذف الدورة بنجاح");
      await refetch();
    } catch {
      toast.error("حدث خطأ أثناء الاتصال بالخادم");
    } finally {
      setDeleteDialog({ open: false, id: null });
    }
  };

  const handleCategorySubmit = async (values: CategoryFormValues) => {
    try {
      const method = editingCategory ? "PATCH" : "POST";
      const payload = editingCategory ? { ...values, id: editingCategory.id } : values;

      const response = await fetch("/api/admin/course-categories", {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      const result = await response.json();

      if (!response.ok) {
        toast.error(result?.error || result?.message || "تعذر حفظ التصنيف");
        return;
      }

      toast.success(editingCategory ? "تم تحديث التصنيف بنجاح" : "تم إنشاء التصنيف بنجاح");
      setCategoryDialogOpen(false);
      setEditingCategory(null);
      categoryForm.reset(defaultCategoryValues);
      await refetchCategories();
      await refetch();
    } catch {
      toast.error("حدث خطأ أثناء الاتصال بالخادم");
    }
  };

  const handleCategoryDelete = async () => {
    if (!categoryDeleteDialog.id) return;

    try {
      const response = await fetch("/api/admin/course-categories", {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: categoryDeleteDialog.id }),
      });
      const result = await response.json();

      if (!response.ok) {
        toast.error(result?.error || result?.message || "تعذر حذف التصنيف");
        return;
      }

      if (selectedCategoryId === categoryDeleteDialog.id) {
        setSelectedCategoryId("all");
      }

      toast.success("تم حذف التصنيف بنجاح");
      await refetchCategories();
      await refetch();
    } catch {
      toast.error("حدث خطأ أثناء الاتصال بالخادم");
    } finally {
      setCategoryDeleteDialog({ open: false, id: null });
    }
  };

  const columns: ColumnDef<Course>[] = [
    {
      accessorKey: "name",
      id: "nameAr",
      header: "الدورة",
      cell: ({ row }) => {
        const course = row.original;

        return (
          <div className="flex items-center gap-4">
            <div className="relative h-14 w-24 overflow-hidden rounded-2xl border border-border/60 bg-muted/40">
              {course.thumbnailUrl ? (
                <img src={course.thumbnailUrl} alt={course.name} className="h-full w-full object-cover" />
              ) : (
                <div className="flex h-full w-full items-center justify-center bg-gradient-to-br from-sky-500/10 to-indigo-500/10">
                  <PlayCircle className="h-6 w-6 text-primary" />
                </div>
              )}
            </div>
            <div className="min-w-0 space-y-1">
              <p className="truncate text-sm font-bold">{course.nameAr || course.name}</p>
              <div className="flex flex-wrap items-center gap-2 text-[11px] text-muted-foreground">
                <span className="inline-flex items-center gap-1">
                  <GraduationCap className="h-3.5 w-3.5" />
                  {course.instructorName || "بدون مدرس"}
                </span>
                {course.code && <span>#{course.code}</span>}
              </div>
            </div>
          </div>
        );
      },
    },
    {
      accessorKey: "price",
      header: "السعر",
      cell: ({ row }) => (
        <div className="flex items-center gap-1 text-sm font-bold text-primary">
          <DollarSign className="h-3.5 w-3.5" />
          {row.original.price || 0} EGP
        </div>
      ),
    },
    {
      accessorKey: "durationHours",
      header: "المدة",
      cell: ({ row }) => (
        <div className="flex items-center gap-1 text-sm font-medium text-muted-foreground">
          <Clock className="h-3.5 w-3.5" />
          {row.original.durationHours || 0} ساعة
        </div>
      ),
    },
    {
      id: "enrollments",
      header: "الملتحقون",
      cell: ({ row }) => (
        <div className="flex items-center gap-1 text-sm font-bold">
          <Users className="h-3.5 w-3.5 text-muted-foreground" />
          {row.original._count?.enrollments || 0}
        </div>
      ),
    },
    {
      id: "topics",
      header: "المحتوى",
      cell: ({ row }) => (
        <div className="flex items-center gap-1 text-sm font-bold">
          <LayoutGrid className="h-3.5 w-3.5 text-muted-foreground" />
          {row.original._count?.topics || 0} وحدة
        </div>
      ),
    },
    {
      accessorKey: "level",
      header: "المستوى",
      cell: ({ row }) => {
        const level = row.original.level || "MEDIUM";
        return (
          <Badge
            variant="outline"
            className={`rounded-full px-2.5 py-0.5 text-[11px] font-bold ${levelStyles[level] || levelStyles.MEDIUM}`}
          >
            {levelLabels[level] || level}
          </Badge>
        );
      },
    },
    {
      accessorKey: "isPublished",
      header: "النشر",
      cell: ({ row }) => (
        <Badge
          variant="outline"
          className={`rounded-full px-2.5 py-0.5 text-[11px] font-bold ${
            row.original.isPublished
              ? "border-emerald-500/20 bg-emerald-500/10 text-emerald-600"
              : "border-border/60 bg-muted/30 text-muted-foreground"
          }`}
        >
          {row.original.isPublished ? "منشورة" : "مسودة"}
        </Badge>
      ),
    },
    {
      accessorKey: "isActive",
      header: "الحالة",
      cell: ({ row }) => (
        <Badge
          variant={row.original.isActive ? "default" : "secondary"}
          className="rounded-full px-2.5 py-0.5 text-[11px] font-bold"
        >
          {row.original.isActive ? "نشطة" : "موقوفة"}
        </Badge>
      ),
    },
    {
      id: "actions",
      header: "إجراءات",
      cell: ({ row }) => (
        <RowActions
          row={row.original}
          onView={(course) => router.push(`/admin/courses/${course.id}`)}
          onEdit={openDialog}
          onDelete={(course) => setDeleteDialog({ open: true, id: course.id })}
          extraActions={[
            {
              icon: BookOpen,
              label: "إدارة المنهج",
              onClick: (course) => router.push(`/admin/courses/${course.id}/curriculum`),
            },
            {
              icon: ExternalLink,
              label: "عرض في الموقع",
              onClick: (course) => router.push(`/courses/${course.id}`),
            },
          ]}
        />
      ),
    },
  ];

  return (
    <div className="space-y-8 pb-20" dir="rtl">
      <PageHeader
        title="إدارة الدورات التعليمية"
        description="أنشئ الدورات، راقب حالة النشر، ووجّه فريق المحتوى بسرعة من شاشة تشغيل واحدة."
        badge={`${pagination?.total || courses.length} دورة`}
      >
        <div className="flex flex-wrap items-center gap-2">
          <AdminButton variant="outline" icon={RefreshCw} onClick={() => refetch()}>
            تحديث
          </AdminButton>
          <AdminButton variant="outline" icon={Tags} onClick={() => openCategoryDialog()}>
            إدارة التصنيفات
          </AdminButton>
          <AdminButton icon={Plus} onClick={() => openDialog()}>
            دورة جديدة
          </AdminButton>
        </div>
      </PageHeader>

      <div className="grid gap-4 xl:grid-cols-[1.35fr_0.65fr]">
        <AdminCard variant="glass" className="overflow-hidden border-white/10 p-0">
          <div className="grid gap-6 border-b border-white/10 bg-gradient-to-l from-slate-950 via-slate-900 to-sky-950 px-6 py-6 text-white lg:grid-cols-[1.1fr_0.9fr]">
            <div className="space-y-4">
              <Badge className="w-fit rounded-full border border-white/10 bg-white/10 px-3 py-1 text-xs font-bold text-white">
                غرفة تشغيل المحتوى
              </Badge>
              <div className="space-y-2">
                <h2 className="text-2xl font-black leading-tight">لوحة مركزة لإطلاق الدورات ومتابعة جاهزيتها</h2>
                <p className="max-w-2xl text-sm leading-7 text-slate-300">
                  راقب الدورات المنشورة، الدورات المتوقفة، وحجم المحتوى داخل كل دورة بدون التنقل بين عدة شاشات.
                </p>
              </div>
              <div className="flex flex-wrap gap-2">
                {filterOptions.map((option) => (
                  <button
                    key={option.key}
                    type="button"
                    onClick={() => setActiveFilter(option.key)}
                    className={`rounded-full border px-4 py-2 text-xs font-bold transition ${
                      activeFilter === option.key
                        ? "border-white bg-white text-slate-950"
                        : "border-white/15 bg-white/5 text-white hover:bg-white/10"
                    }`}
                  >
                    {option.label}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid gap-3 sm:grid-cols-2">
              <div className="rounded-3xl border border-white/10 bg-white/5 p-4">
                <p className="text-xs font-bold text-slate-300">الدورات المنشورة</p>
                <p className="mt-3 text-3xl font-black">{publishedCoursesCount}</p>
                <p className="mt-2 text-xs text-slate-400">جاهزة للعرض للطلاب الآن</p>
              </div>
              <div className="rounded-3xl border border-white/10 bg-white/5 p-4">
                <p className="text-xs font-bold text-slate-300">الدورات النشطة</p>
                <p className="mt-3 text-3xl font-black">{activeCoursesCount}</p>
                <p className="mt-2 text-xs text-slate-400">متاحة ضمن عمليات المنصة</p>
              </div>
              <div className="rounded-3xl border border-white/10 bg-white/5 p-4">
                <p className="text-xs font-bold text-slate-300">إجمالي الوحدات</p>
                <p className="mt-3 text-3xl font-black">{totalCurriculumUnits}</p>
                <p className="mt-2 text-xs text-slate-400">حجم المحتوى عبر جميع الدورات</p>
              </div>
              <div className="rounded-3xl border border-white/10 bg-white/5 p-4">
                <p className="text-xs font-bold text-slate-300">متوسط السعر</p>
                <p className="mt-3 text-3xl font-black">{averagePrice} EGP</p>
                <p className="mt-2 text-xs text-slate-400">يساعد في ضبط التسعير العام</p>
              </div>
            </div>
          </div>
        </AdminCard>

        <AdminCard variant="outline" className="space-y-4 p-5">
          <div className="flex items-center gap-2 text-sm font-bold">
            <Filter className="h-4 w-4 text-primary" />
            فلاتر تشغيل سريعة
          </div>

          <div className="space-y-3">
            <label className="space-y-2 text-sm">
              <span className="font-medium text-foreground">التصنيف</span>
              <Select value={selectedCategoryId} onValueChange={setSelectedCategoryId}>
                <SelectTrigger>
                  <SelectValue placeholder="كل التصنيفات" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">كل التصنيفات</SelectItem>
                  {categories.map((category) => (
                    <SelectItem key={category.id} value={category.id}>
                      {category.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </label>

            <label className="space-y-2 text-sm">
              <span className="font-medium text-foreground">المدرس</span>
              <Select value={selectedTeacherId} onValueChange={setSelectedTeacherId}>
                <SelectTrigger>
                  <SelectValue placeholder="كل المدرسين" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">كل المدرسين</SelectItem>
                  {teachers.map((teacher) => (
                    <SelectItem key={teacher.id} value={teacher.id}>
                      {teacher.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </label>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div className="rounded-2xl bg-muted/40 p-4">
              <p className="text-[11px] font-bold text-muted-foreground">الملتحقون</p>
              <p className="mt-2 text-2xl font-black">{totalEnrollments}</p>
            </div>
            <div className="rounded-2xl bg-muted/40 p-4">
              <p className="text-[11px] font-bold text-muted-foreground">الساعات</p>
              <p className="mt-2 text-2xl font-black">{totalHours}</p>
            </div>
          </div>

          <div className="rounded-2xl border border-dashed border-primary/20 bg-primary/5 p-4 text-sm leading-7 text-muted-foreground">
            أسرع مسار للعمل: أنشئ الدورة، اربطها بالمدرس، أضف الصورة والفيديو، ثم انقلها إلى "منشورة" عندما يصبح المنهج جاهزًا.
          </div>

          <div className="space-y-3 rounded-3xl border border-border/60 bg-background/70 p-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2 text-sm font-bold">
                <Tags className="h-4 w-4 text-primary" />
                التصنيفات التعليمية
              </div>
              <button
                type="button"
                onClick={() => openCategoryDialog()}
                className="text-xs font-bold text-primary transition hover:opacity-80"
              >
                إضافة تصنيف
              </button>
            </div>
            <div className="space-y-2">
              {categories.slice(0, 6).map((category) => (
                <div key={category.id} className="flex items-center justify-between rounded-2xl bg-muted/30 px-3 py-2">
                  <div className="min-w-0">
                    <p className="truncate text-sm font-bold">{category.name}</p>
                    <p className="text-[11px] text-muted-foreground">{category.coursesCount} دورة</p>
                  </div>
                  <div className="flex items-center gap-1">
                    <button
                      type="button"
                      onClick={() => openCategoryDialog(category)}
                      className="rounded-xl p-2 text-muted-foreground transition hover:bg-muted hover:text-foreground"
                    >
                      <Pencil className="h-3.5 w-3.5" />
                    </button>
                    <button
                      type="button"
                      onClick={() => setCategoryDeleteDialog({ open: true, id: category.id })}
                      className="rounded-xl p-2 text-muted-foreground transition hover:bg-destructive/10 hover:text-destructive"
                    >
                      <Trash2 className="h-3.5 w-3.5" />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </AdminCard>
      </div>

      <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
        <AdminCard className="space-y-3 p-5">
          <div className="flex items-center justify-between">
            <span className="text-xs font-bold text-muted-foreground">إجمالي الدورات</span>
            <PlayCircle className="h-4 w-4 text-primary" />
          </div>
          <p className="text-3xl font-black">{courses.length}</p>
          <p className="text-sm text-muted-foreground">جميع السجلات التعليمية في لوحة التحكم.</p>
        </AdminCard>
        <AdminCard className="space-y-3 p-5">
          <div className="flex items-center justify-between">
            <span className="text-xs font-bold text-muted-foreground">الدورات المنشورة</span>
            <Sparkles className="h-4 w-4 text-emerald-500" />
          </div>
          <p className="text-3xl font-black">{publishedCoursesCount}</p>
          <p className="text-sm text-muted-foreground">جاهزة للظهور للطلاب في الواجهة التعليمية.</p>
        </AdminCard>
        <AdminCard className="space-y-3 p-5">
          <div className="flex items-center justify-between">
            <span className="text-xs font-bold text-muted-foreground">المحتوى المتاح</span>
            <LayoutGrid className="h-4 w-4 text-violet-500" />
          </div>
          <p className="text-3xl font-black">{totalCurriculumUnits}</p>
          <p className="text-sm text-muted-foreground">وحدة تعليمية موزعة على الدورات الحالية.</p>
        </AdminCard>
        <AdminCard className="space-y-3 p-5">
          <div className="flex items-center justify-between">
            <span className="text-xs font-bold text-muted-foreground">السعر المتوسط</span>
            <Award className="h-4 w-4 text-amber-500" />
          </div>
          <p className="text-3xl font-black">{averagePrice} EGP</p>
          <p className="text-sm text-muted-foreground">مرجع سريع عند تسعير دورة جديدة.</p>
        </AdminCard>
      </div>

      <AdminDataTable
        columns={columns}
        data={courses}
        loading={isLoading}
        serverSide
        totalRows={pagination?.total || 0}
        pageCount={pagination?.totalPages || 1}
        currentPage={page}
        onPageChange={setPage}
        onPageSizeChange={setLimit}
        pageSize={limit}
        actions={{ onRefresh: () => refetch() }}
        emptyMessage={{
          title: "لا توجد دورات مطابقة",
          description: "جرّب تغيير الفلاتر أو أنشئ دورة جديدة لبدء المحتوى.",
        }}
        toolbar={
          <div className="flex flex-wrap items-center gap-2 text-xs text-muted-foreground">
            <div className="relative">
              <Search className="absolute right-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
              <input
                type="text"
                value={search}
                onChange={(event) => setSearch(event.target.value)}
                placeholder="???? ???? ?????? ?? ?????"
                className="h-10 w-64 rounded-xl border border-border bg-accent/20 px-10 text-sm outline-none ring-primary transition focus:ring-1"
              />
            </div>
            <span className="rounded-full bg-muted px-3 py-2 font-medium">
              {pagination?.total || courses.length} نتيجة
            </span>
            {(activeFilter !== "all" || selectedCategoryId !== "all" || selectedTeacherId !== "all" || search) && (
              <button
                type="button"
                onClick={() => {
                  setActiveFilter("all");
                  setSelectedCategoryId("all");
                  setSelectedTeacherId("all");
                  setSearch("");
                }}
                className="rounded-full border px-3 py-2 font-medium text-foreground transition hover:bg-muted"
              >
                تصفير الفلاتر
              </button>
            )}
          </div>
        }
      />

      <Dialog
        open={dialogOpen}
        onOpenChange={(open) => {
          setDialogOpen(open);
          if (!open) {
            setEditingCourse(null);
            form.reset(defaultValues);
          }
        }}
      >
        <DialogContent className="max-w-5xl rounded-[2rem] p-0">
          <div className="grid max-h-[88vh] gap-0 overflow-hidden lg:grid-cols-[1.1fr_0.9fr]">
            <div className="overflow-y-auto p-6 sm:p-8" dir="rtl">
              <DialogHeader className="space-y-2 text-right">
                <DialogTitle className="text-2xl font-black">
                  {editingCourse ? "تعديل الدورة" : "إضافة دورة جديدة"}
                </DialogTitle>
                <p className="text-sm text-muted-foreground">
                  أدخل البيانات الأساسية أولًا، ثم أضف الوسائط والمتطلبات قبل النشر.
                </p>
              </DialogHeader>

              <Form {...form}>
                <form onSubmit={form.handleSubmit(handleSubmit)} className="mt-6 space-y-6">
                  <div className="grid gap-4 sm:grid-cols-2">
                    <FormField
                      control={form.control}
                      name="nameAr"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>اسم الدورة بالعربية</FormLabel>
                          <FormControl>
                            <Input {...field} value={field.value || ""} placeholder="مثال: أساسيات اللغة العربية" />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="name"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>اسم الدورة بالإنجليزية</FormLabel>
                          <FormControl>
                            <Input {...field} value={field.value || ""} placeholder="Arabic Foundations" />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <FormField
                    control={form.control}
                    name="description"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>الوصف</FormLabel>
                        <FormControl>
                          <Textarea
                            {...field}
                            value={field.value || ""}
                            className="min-h-[110px]"
                            placeholder="ملخص واضح لما سيتعلمه الطالب داخل الدورة."
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <div className="grid gap-4 sm:grid-cols-2">
                    <FormField
                      control={form.control}
                      name="requirements"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>المتطلبات</FormLabel>
                          <FormControl>
                            <Textarea
                              {...field}
                              value={field.value || ""}
                              placeholder={"اكتب كل متطلب في سطر منفصل"}
                              className="min-h-[120px]"
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="learningObjectives"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>مخرجات التعلم</FormLabel>
                          <FormControl>
                            <Textarea
                              {...field}
                              value={field.value || ""}
                              placeholder={"اكتب كل هدف تعليمي في سطر منفصل"}
                              className="min-h-[120px]"
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <div className="grid gap-4 sm:grid-cols-3">
                    <FormField
                      control={form.control}
                      name="price"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>السعر</FormLabel>
                          <FormControl>
                            <Input type="number" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="durationHours"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>عدد الساعات</FormLabel>
                          <FormControl>
                            <Input type="number" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="level"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>المستوى</FormLabel>
                          <Select onValueChange={field.onChange} value={field.value}>
                            <FormControl>
                              <SelectTrigger>
                                <SelectValue />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              <SelectItem value="EASY">مبتدئ</SelectItem>
                              <SelectItem value="MEDIUM">متوسط</SelectItem>
                              <SelectItem value="HARD">متقدم</SelectItem>
                              <SelectItem value="EXPERT">خبير</SelectItem>
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <div className="grid gap-4 sm:grid-cols-2">
                    <FormField
                      control={form.control}
                      name="instructorId"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>المدرس</FormLabel>
                          <Select onValueChange={field.onChange} value={field.value || ""}>
                            <FormControl>
                              <SelectTrigger>
                                <SelectValue placeholder="اختر المدرس" />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              {teachers.map((teacher) => (
                                <SelectItem key={teacher.id} value={teacher.id}>
                                  {teacher.name}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="categoryId"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>التصنيف</FormLabel>
                          <Select onValueChange={field.onChange} value={field.value || ""}>
                            <FormControl>
                              <SelectTrigger>
                                <SelectValue placeholder="اختر التصنيف" />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              {categories.map((category) => (
                                <SelectItem key={category.id} value={category.id}>
                                  {category.name}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <div className="grid gap-6 sm:grid-cols-2">
                    <FormField
                      control={form.control}
                      name="thumbnailUrl"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>صورة الدورة</FormLabel>
                          <FormControl>
                            <div className="space-y-3">
                              <Input {...field} value={field.value || ""} placeholder="رابط مباشر للصورة" />
                              <AdminUpload
                                accept="image/*"
                                label="رفع صورة من الجهاز"
                                onUploadComplete={(url) => field.onChange(url)}
                              />
                            </div>
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="trailerUrl"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>فيديو تعريفي</FormLabel>
                          <FormControl>
                            <div className="space-y-3">
                              <Input {...field} value={field.value || ""} placeholder="رابط فيديو مباشر أو يوتيوب" />
                              <AdminUpload
                                accept="video/*"
                                label="رفع فيديو من الجهاز"
                                onUploadComplete={(url) => field.onChange(url)}
                              />
                            </div>
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <div className="grid gap-4 sm:grid-cols-2">
                    <div className="flex items-center justify-between rounded-3xl border bg-muted/20 p-4">
                      <div className="space-y-1">
                        <p className="font-bold">الحالة</p>
                        <p className="text-xs text-muted-foreground">عند إيقافها لن تظهر ضمن التشغيل المعتاد.</p>
                      </div>
                      <FormField
                        control={form.control}
                        name="isActive"
                        render={({ field }) => (
                          <FormControl>
                            <Switch checked={field.value} onCheckedChange={field.onChange} />
                          </FormControl>
                        )}
                      />
                    </div>
                    <div className="flex items-center justify-between rounded-3xl border bg-muted/20 p-4">
                      <div className="space-y-1">
                        <p className="font-bold">النشر</p>
                        <p className="text-xs text-muted-foreground">فعّل النشر عندما تكون الدورة جاهزة للطلاب.</p>
                      </div>
                      <FormField
                        control={form.control}
                        name="isPublished"
                        render={({ field }) => (
                          <FormControl>
                            <Switch checked={field.value} onCheckedChange={field.onChange} />
                          </FormControl>
                        )}
                      />
                    </div>
                  </div>

                  <DialogFooter>
                    <AdminButton type="submit" className="h-12 w-full text-base font-black" icon={RefreshCw}>
                      {editingCourse ? "حفظ التعديلات" : "إنشاء الدورة"}
                    </AdminButton>
                  </DialogFooter>
                </form>
              </Form>
            </div>

            <div className="border-r bg-muted/20 p-6 sm:p-8" dir="rtl">
              <div className="space-y-5">
                <div>
                  <p className="text-xs font-bold uppercase tracking-[0.2em] text-muted-foreground">
                    معاينة سريعة
                  </p>
                  <h3 className="mt-2 text-2xl font-black">{previewName}</h3>
                </div>

                <div className="overflow-hidden rounded-[1.75rem] border bg-background">
                  <div className="relative aspect-[16/10] w-full bg-gradient-to-br from-sky-500/10 via-background to-indigo-500/10">
                    {previewThumbnail ? (
                      <img src={previewThumbnail} alt={previewName} className="h-full w-full object-cover" />
                    ) : (
                      <div className="flex h-full items-center justify-center">
                        <PlayCircle className="h-12 w-12 text-primary" />
                      </div>
                    )}
                  </div>
                  <div className="space-y-4 p-5">
                    <div className="flex flex-wrap gap-2">
                      <Badge variant="outline" className={`rounded-full ${levelStyles[previewLevel] || levelStyles.MEDIUM}`}>
                        {levelLabels[previewLevel] || previewLevel}
                      </Badge>
                      <Badge
                        variant="outline"
                        className={previewPublished ? "rounded-full border-emerald-500/20 bg-emerald-500/10 text-emerald-600" : "rounded-full"}
                      >
                        {previewPublished ? "منشورة" : "مسودة"}
                      </Badge>
                      <Badge variant={previewActive ? "default" : "secondary"} className="rounded-full">
                        {previewActive ? "نشطة" : "موقوفة"}
                      </Badge>
                    </div>

                    <p className="text-sm leading-7 text-muted-foreground">{previewDescription}</p>

                    <div className="grid grid-cols-2 gap-3">
                      <div className="rounded-2xl bg-muted/40 p-4">
                        <p className="text-[11px] font-bold text-muted-foreground">السعر</p>
                        <p className="mt-2 text-lg font-black">{previewPrice || 0} EGP</p>
                      </div>
                      <div className="rounded-2xl bg-muted/40 p-4">
                        <p className="text-[11px] font-bold text-muted-foreground">المدة</p>
                        <p className="mt-2 text-lg font-black">{previewDuration || 0} ساعة</p>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="rounded-[1.5rem] border border-dashed bg-background p-5">
                  <p className="text-sm font-bold">توصية تشغيل</p>
                  <p className="mt-2 text-sm leading-7 text-muted-foreground">
                    قبل النشر، تأكد من وجود مدرس مرتبط، وصف واضح، وصورة مناسبة حتى تظهر الدورة بشكل مكتمل في صفحة التعليم.
                  </p>
                </div>
              </div>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      <Dialog
        open={categoryDialogOpen}
        onOpenChange={(open) => {
          setCategoryDialogOpen(open);
          if (!open) {
            setEditingCategory(null);
            categoryForm.reset(defaultCategoryValues);
          }
        }}
      >
        <DialogContent className="max-w-2xl rounded-[2rem] p-0">
          <div className="p-6 sm:p-8" dir="rtl">
            <DialogHeader className="space-y-2 text-right">
              <DialogTitle className="text-2xl font-black">
                {editingCategory ? "تعديل تصنيف دورة" : "إضافة تصنيف دورة"}
              </DialogTitle>
              <p className="text-sm text-muted-foreground">
                استخدم التصنيفات لتنظيم الدورات التعليمية وتسهيل الفرز داخل لوحة الأدمن وواجهة الطالب.
              </p>
            </DialogHeader>

            <Form {...categoryForm}>
              <form onSubmit={categoryForm.handleSubmit(handleCategorySubmit)} className="mt-6 space-y-5">
                <div className="grid gap-4 sm:grid-cols-2">
                  <FormField
                    control={categoryForm.control}
                    name="name"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>اسم التصنيف</FormLabel>
                        <FormControl>
                          <Input {...field} value={field.value || ""} placeholder="مثال: الأحياء" />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={categoryForm.control}
                    name="slug"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>الرابط المختصر</FormLabel>
                        <FormControl>
                          <Input {...field} value={field.value || ""} placeholder="biology-courses" />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>
                <div className="grid gap-4 sm:grid-cols-2">
                  <FormField
                    control={categoryForm.control}
                    name="icon"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>اسم الأيقونة</FormLabel>
                        <FormControl>
                          <Input {...field} value={field.value || ""} placeholder="BookOpen" />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <div className="rounded-3xl border bg-muted/20 p-4">
                    <p className="text-xs font-bold text-muted-foreground">عدد الدورات المرتبطة</p>
                    <p className="mt-2 text-3xl font-black">{editingCategory?.coursesCount ?? 0}</p>
                  </div>
                </div>
                <FormField
                  control={categoryForm.control}
                  name="description"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>الوصف</FormLabel>
                      <FormControl>
                        <Textarea
                          {...field}
                          value={field.value || ""}
                          className="min-h-[110px]"
                          placeholder="وصف مختصر يساعد فريق المحتوى على فهم استخدام هذا التصنيف."
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <DialogFooter className="gap-2 sm:justify-start">
                  <AdminButton type="submit" icon={editingCategory ? Pencil : Plus}>
                    {editingCategory ? "حفظ التعديلات" : "إنشاء التصنيف"}
                  </AdminButton>
                  <AdminButton
                    type="button"
                    variant="outline"
                    onClick={() => {
                      setCategoryDialogOpen(false);
                      setEditingCategory(null);
                      categoryForm.reset(defaultCategoryValues);
                    }}
                  >
                    إلغاء
                  </AdminButton>
                </DialogFooter>
              </form>
            </Form>
          </div>
        </DialogContent>
      </Dialog>

      <ConfirmDialog
        open={deleteDialog.open}
        onOpenChange={(open) => setDeleteDialog({ open, id: open ? deleteDialog.id : null })}
        onConfirm={handleDelete}
        title="حذف الدورة"
        description="سيتم حذف الدورة نهائيًا إذا لم تكن مرتبطة بطلاب أو سجلات تمنع ذلك."
      />
      <ConfirmDialog
        open={categoryDeleteDialog.open}
        onOpenChange={(open) => setCategoryDeleteDialog({ open, id: open ? categoryDeleteDialog.id : null })}
        onConfirm={handleCategoryDelete}
        title="حذف التصنيف"
        description="سيتم حذف التصنيف نهائيًا إذا لم يكن مرتبطًا بأي دورة تعليمية."
        confirmText="حذف التصنيف"
        variant="destructive"
      />
    </div>
  );
}

"use client";

import * as React from "react";
import { PageHeader } from "@/components/admin/ui/page-header";
import { AdminDataTable, RowActions } from "@/components/admin/ui/admin-table";
import { AdminButton } from "@/components/admin/ui/admin-button";
import { AdminCard, AdminStatsCard } from "@/components/admin/ui/admin-card";
import { Badge } from "@/components/ui/badge";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { 
  Plus, Library, BookOpen, Globe, FileVideo, 
  ScrollText, ExternalLink, Link, FileText, Video, 
  File, Sparkles, Hammer, Trash2, Download, Upload,
  Database, ShieldCheck, Zap
} from "lucide-react";
import { ColumnDef } from "@tanstack/react-table";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { toast } from "sonner";
import { ConfirmDialog } from "@/components/admin/ui/confirm-dialog";
import { TableSkeleton } from "@/components/admin/ui/loading-skeleton";
import { motion } from "framer-motion";

interface Subject {
  id: string;
  name: string;
  nameAr: string | null;
  color: string | null;
}

interface Resource {
  id: string;
  title: string;
  description: string | null;
  url: string;
  type: string;
  source: string | null;
  free: boolean;
  createdAt: string;
  subject: {
    id: string;
    name: string;
    nameAr: string | null;
    color: string | null;
  };
}

const resourceSchema = z.object({
  title: z.string().min(1, "عنوان المخطوطة مطلوب"),
  description: z.string().optional(),
  url: z.string().url("رابط البوابة غير صالح"),
  type: z.string().min(1, "نوع المصدر مطلوب"),
  source: z.string().optional(),
  free: z.boolean(),
  subjectId: z.string().min(1, "يجب تحديد العلم التابع له"),
});

type ResourceFormValues = z.infer<typeof resourceSchema>;

const resourceTypes = [
  { value: "link", label: "بوابة خارجية", icon: Link, color: "blue" },
  { value: "video", label: "مخطوطة مرئية", icon: Video, color: "red" },
  { value: "pdf", label: "ببردية PDF", icon: FileText, color: "green" },
  { value: "document", label: "وثيقة علمية", icon: File, color: "purple" },
];

export default function AdminResourcesPage() {
  const [resources, setResources] = React.useState<Resource[]>([]);
  const [subjects, setSubjects] = React.useState<Subject[]>([]);
  const [loading, setLoading] = React.useState(true);
  const [dialogOpen, setDialogOpen] = React.useState(false);
  const [editingResource, setEditingResource] = React.useState<Resource | null>(null);
  const [deleteDialog, setDeleteDialog] = React.useState<{
    open: boolean;
    id: string | null;
  }>({ open: false, id: null });

  const form = useForm<ResourceFormValues>({
    resolver: zodResolver(resourceSchema),
    defaultValues: {
      title: "",
      description: "",
      url: "",
      type: "link",
      source: "",
      free: true,
      subjectId: "",
    },
  });

  const fetchResources = React.useCallback(async () => {
    setLoading(true);
    try {
      const response = await fetch("/api/admin/resources");
      const data = await response.json();
      setResources(data.resources || []);
    } catch (error) {
      console.error("Error fetching resources:", error);
      toast.error("حدث خطأ في استدعاء سجلات الأرشيف");
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchSubjects = React.useCallback(async () => {
    try {
      const response = await fetch("/api/admin/subjects?limit=100");
      const data = await response.json();
      setSubjects(data.subjects || []);
    } catch (error) {
      console.error("Error fetching subjects:", error);
    }
  }, []);

  React.useEffect(() => {
    fetchResources();
    fetchSubjects();
  }, [fetchResources, fetchSubjects]);

  const handleOpenDialog = (resource?: Resource) => {
    if (resource) {
      setEditingResource(resource);
      form.reset({
        title: resource.title,
        description: resource.description || "",
        url: resource.url,
        type: resource.type,
        source: resource.source || "",
        free: resource.free,
        subjectId: resource.subject.id,
      });
    } else {
      setEditingResource(null);
      form.reset({
        title: "",
        description: "",
        url: "",
        type: "link",
        source: "",
        free: true,
        subjectId: "",
      });
    }
    setDialogOpen(true);
  };

  const handleSubmit = async (values: ResourceFormValues) => {
    try {
      const url = "/api/admin/resources";
      const method = editingResource ? "PATCH" : "POST";
      const body = editingResource ? { ...values, id: editingResource.id } : values;

      const response = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body),
      });

      if (response.ok) {
        toast.success(editingResource ? "تم تحديث ميثاق المورد" : "تم حفظ مورد جديد في الأرشيف الإمبراطوري");
        setDialogOpen(false);
        fetchResources();
      } else {
        toast.error("فشل في تدوين المورد");
      }
    } catch (error) {
      console.error("Error saving resource:", error);
      toast.error("خطأ في الاتصال بالأرشيف");
    }
  };

  const handleDelete = async () => {
    if (!deleteDialog.id) return;

    try {
      const response = await fetch("/api/admin/resources", {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: deleteDialog.id }),
      });

      if (response.ok) {
        toast.success("تم مسح المورد من السجلات");
        fetchResources();
      } else {
        toast.error("فشل في الإتلاف");
      }
    } catch (error) {
      console.error("Error deleting resource:", error);
      toast.error("خطأ في الاتصال");
    } finally {
      setDeleteDialog({ open: false, id: null });
    }
  };

  const columns: ColumnDef<Resource>[] = [
    {
      accessorKey: "title",
      header: "المورد / المخطوطة",
      cell: ({ row }) => {
        const resource = row.original;
        const typeInfo = resourceTypes.find(t => t.value === resource.type);
        const Icon = typeInfo?.icon || Link;
        return (
          <div className="flex items-center gap-4">
            <div 
              className="flex h-12 w-12 items-center justify-center rounded-[1rem] border border-white/10 shadow-sm transition-transform hover:scale-105"
              style={{ backgroundColor: `${resource.subject.color || "#3b82f6"}20`, color: resource.subject.color || "#3b82f6" }}
            >
              <Icon className="h-6 w-6" />
            </div>
            <div>
              <p className="font-black text-sm tracking-tight">{resource.title}</p>
              <div className="flex items-center gap-2 mt-0.5">
                <span className="text-[10px] text-muted-foreground font-bold uppercase tracking-widest opacity-60">
                  {resource.source || "إدارة الإمبراطورية"}
                </span>
                <Badge variant="outline" className="text-[8px] h-3 px-1 border-white/5 bg-white/5">
                  {resource.type}
                </Badge>
              </div>
            </div>
          </div>
        );
      },
    },
    {
      accessorKey: "subject",
      header: "العلم التابع له",
      cell: ({ row }) => {
        const resource = row.original;
        return (
          <Badge 
            variant="outline" 
            className="font-black text-[10px] border-2 px-3 py-1 bg-white/5 opacity-80"
            style={{ borderColor: `${resource.subject.color || "#3b82f6"}40`, color: resource.subject.color || "#3b82f6" }}
          >
            {resource.subject.nameAr || resource.subject.name}
          </Badge>
        );
      },
    },
    {
      accessorKey: "free",
      header: "رتبة الوصول",
      cell: ({ row }) => {
        const free = row.getValue("free") as boolean;
        return (
          <div className="flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full ${free ? "bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]" : "bg-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.5)]"}`} />
            <span className={`text-[10px] font-black uppercase tracking-widest ${free ? "text-emerald-500" : "text-amber-500"}`}>
              {free ? "متاح للعامة" : "للحاصلين على التصريح"}
            </span>
          </div>
        );
      },
    },
    {
      accessorKey: "createdAt",
      header: "تاريخ الأرشفة",
      cell: ({ row }) => (
        <span className="text-xs font-bold text-muted-foreground">
          {new Date(row.original.createdAt).toLocaleDateString("ar-EG")}
        </span>
      ),
    },
    {
      id: "actions",
      header: "التحكم الملكي",
      cell: ({ row }) => (
        <RowActions
          row={row.original}
          onEdit={handleOpenDialog}
          onDelete={(r) => setDeleteDialog({ open: true, id: r.id })}
          extraActions={[
            { 
              icon: ExternalLink, 
              label: "فتح البوابة", 
              onClick: (r) => window.open(r.url, "_blank") 
            },
          ]}
        />
      ),
    },
  ];

  return (
    <div className="space-y-10 pb-20" dir="rtl">
      <PageHeader
        title="أرشيف الموارد الإمبراطوري 📚"
        description="إدارة المكتبة المركزية، المخطوطات العلمية، وبوابات التعلم الخارجية لجيش المحاربين."
      >
        <div className="flex items-center gap-3">
          <AdminButton variant="outline" icon={Download}>تصدير الأرشيف</AdminButton>
          <AdminButton icon={Plus} onClick={() => handleOpenDialog()}>إضافة مورد جديد</AdminButton>
        </div>
      </PageHeader>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <AdminStatsCard 
          title="إجمالي المخطوطات" 
          value={resources.length} 
          icon={Library} 
          color="blue"
          description="مورد مؤرشف حالياً"
        />
        <AdminStatsCard 
          title="بوابات مرئية" 
          value={resources.filter(r => r.type === "video").length} 
          icon={FileVideo} 
          color="red"
          description="دروس فيديو خارجية"
        />
        <AdminStatsCard 
          title="برديات PDF" 
          value={resources.filter(r => r.type === "pdf").length} 
          icon={ScrollText} 
          color="green"
          description="ملفات دراسية محملة"
        />
        <AdminStatsCard 
          title="موارد مجانية" 
          value={resources.filter(r => r.free).length} 
          icon={Zap} 
          color="yellow"
          description="متاحة لكافة المحاربين"
        />
      </div>

      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="rpg-glass-light dark:rpg-glass p-1 rounded-[2.5rem] border border-white/10 overflow-hidden shadow-2xl"
      >
        {loading ? (
          <TableSkeleton rows={8} cols={5} />
        ) : (
          <AdminDataTable
            columns={columns}
            data={resources}
            searchKey="title"
            searchPlaceholder="ابحث في رفوف الأرشيف..."
            actions={{ onRefresh: () => fetchResources() }}
            bulkActions={[
              {
                label: "إتلاف السجلات المحددة",
                icon: Trash2,
                variant: "destructive",
                onClick: async (rows) => {
                  const ids = rows.map(r => r.id);
                  if (confirm(`هل أنت متأكد من مسح ${ids.length} مورد من التاريخ؟`)) {
                    try {
                      const res = await fetch("/api/admin/resources", {
                        method: "DELETE",
                        headers: { "Content-Type": "application/json" },
                        body: JSON.stringify({ ids }),
                      });
                      if (res.ok) {
                        toast.success("تم تنظيف الأرشيف بنجاح");
                        fetchResources();
                      }
                    } catch (_err) {
                      toast.error("فشل في عملية التطهير");
                    }
                  }
                }
              },
              {
                label: "إتاحة للعامة (مجاني)",
                icon: ShieldCheck,
                onClick: async (rows) => {
                  const ids = rows.map(r => r.id);
                  try {
                    const res = await fetch("/api/admin/resources", {
                      method: "PATCH",
                      headers: { "Content-Type": "application/json" },
                      body: JSON.stringify({ ids, free: true }),
                    });
                    if (res.ok) {
                      toast.success("تم فتح بوابات الوصول");
                      fetchResources();
                    }
                  } catch (_err) {
                    toast.error("حدث خطأ في تحديث ميثاق الوصول");
                  }
                }
              }
            ]}
          />
        )}
      </motion.div>

      {/* Add/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-lg bg-card/80 backdrop-blur-xl border-white/10 rounded-[2.5rem] p-0 overflow-hidden shadow-2xl">
          <div className="h-1.5 bg-gradient-to-r from-blue-500 via-indigo-500 to-purple-500" />
          <div className="p-8">
            <DialogHeader className="mb-8">
              <DialogTitle className="text-2xl font-black flex items-center gap-3">
                {editingResource ? (
                  <>
                    <Hammer className="w-7 h-7 text-indigo-500" />
                    تنقيح بيانات المخطوطة
                  </>
                ) : (
                  <>
                    <Database className="w-7 h-7 text-blue-500" />
                    أرشفة مورد جديد
                  </>
                )}
              </DialogTitle>
              <DialogDescription className="font-bold text-muted-foreground">
                أدخل بيانات المورد بدقة لتسهيل وصول المحاربين إلى شعلة المعرفة.
              </DialogDescription>
            </DialogHeader>

            <Form {...form}>
              <form onSubmit={form.handleSubmit(handleSubmit)} className="space-y-6">
                <FormField
                  control={form.control}
                  name="title"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">عنوان المورد</FormLabel>
                      <FormControl>
                        <Input {...field} placeholder="كتاب الملحمة الكبرى..." className="rounded-xl border-white/10 bg-white/5 h-12 px-6 font-bold" />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <div className="grid grid-cols-2 gap-4">
                  <FormField
                    control={form.control}
                    name="subjectId"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">العلم التابع له</FormLabel>
                        <Select onValueChange={field.onChange} value={field.value}>
                          <FormControl>
                            <SelectTrigger className="rounded-xl border-white/10 bg-white/5 h-12">
                              <SelectValue placeholder="اختر المادة" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent className="rounded-xl border-white/10">
                            {subjects.map((subject) => (
                              <SelectItem key={subject.id} value={subject.id} className="font-bold cursor-pointer">
                                {subject.nameAr || subject.name}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="type"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">صنف المورد</FormLabel>
                        <Select onValueChange={field.onChange} value={field.value}>
                          <FormControl>
                            <SelectTrigger className="rounded-xl border-white/10 bg-white/5 h-12">
                              <SelectValue placeholder="اختر النوع" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent className="rounded-xl border-white/10">
                            {resourceTypes.map((type) => (
                              <SelectItem key={type.value} value={type.value} className="font-bold cursor-pointer">
                                <div className="flex items-center gap-2">
                                  <type.icon className={`w-3.5 h-3.5 text-${type.color}-500`} />
                                  <span>{type.label}</span>
                                </div>
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>

                <FormField
                  control={form.control}
                  name="url"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">رابط البوابة (URL)</FormLabel>
                      <FormControl>
                        <div className="relative">
                          <Link className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground opacity-50" />
                          <Input {...field} type="url" dir="ltr" className="rounded-xl border-white/10 bg-white/5 h-12 pl-10 pr-6 font-mono text-xs" />
                        </div>
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <div className="grid grid-cols-2 gap-4">
                  <FormField
                    control={form.control}
                    name="source"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">جهة الإصدار</FormLabel>
                        <FormControl>
                          <Input {...field} placeholder="إدارة Thanawy..." className="rounded-xl border-white/10 bg-white/5 h-11 px-4 font-bold" />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="free"
                    render={({ field }) => (
                      <FormItem className="flex items-center justify-between rounded-xl border border-white/10 p-3 bg-white/5">
                        <div className="space-y-0.5">
                          <FormLabel className="font-black text-[10px] uppercase tracking-widest">إتاحة للعامة؟</FormLabel>
                        </div>
                        <FormControl>
                          <Switch
                            checked={field.value}
                            onCheckedChange={field.onChange}
                          />
                        </FormControl>
                      </FormItem>
                    )}
                  />
                </div>

                <FormField
                  control={form.control}
                  name="description"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">حاشية مختصرة (وصف)</FormLabel>
                      <FormControl>
                        <Textarea {...field} className="rounded-2xl border-white/10 bg-white/5 p-4 min-h-[80px]" />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <DialogFooter className="pt-4">
                  <AdminButton type="submit" icon={editingResource ? Sparkles : Plus} className="w-full h-14 text-md font-black shadow-xl rounded-2xl">
                    {editingResource ? "تحديث السجل" : "أرشفة المخطوطة"}
                  </AdminButton>
                </DialogFooter>
              </form>
            </Form>
          </div>
        </DialogContent>
      </Dialog>

      <ConfirmDialog
        open={deleteDialog.open}
        onOpenChange={(open) => setDeleteDialog({ open, id: null })}
        title="إتلاف المورد نهائياً؟"
        description="أنت على وشك حرق سجلات هذه المخطوطة من الأرشيف تماماً. هل أنت متأكد؟"
        confirmText="نعم، أتلف السجل"
        variant="destructive"
        onConfirm={handleDelete}
      />
    </div>
  );
}

"use client";

import * as React from "react";
import { PageHeader } from "@/components/admin/ui/page-header";
import { AdminDataTable, RowActions } from "@/components/admin/ui/admin-table";
import { AdminButton } from "@/components/admin/ui/admin-button";
import { AdminCard, AdminStatsCard } from "@/components/admin/ui/admin-card";
import { Badge } from "@/components/ui/badge";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { 
  Plus, Edit, Trash2, Crown, Calendar, 
  Flame, Swords, Target, Shield, Sparkles,
  Zap, History, Timer, Trophy, Hammer
} from "lucide-react";
import { ColumnDef } from "@tanstack/react-table";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { toast } from "sonner";
import { ConfirmDialog } from "@/components/admin/ui/confirm-dialog";
import { TableSkeleton } from "@/components/admin/ui/loading-skeleton";
import { motion } from "framer-motion";

interface Season {
  id: string;
  name: string;
  description: string | null;
  startDate: string;
  endDate: string;
  isActive: boolean;
  rewards: string | null;
  createdAt: string;
  _count: {
    participations: number;
    leaderboards: number;
  };
}

const seasonSchema = z.object({
  name: z.string().min(1, "اسم الموسم مطلوب"),
  description: z.string().optional(),
  startDate: z.string().min(1, "تاريخ البداية مطلوب"),
  endDate: z.string().min(1, "تاريخ النهاية مطلوب"),
  isActive: z.boolean(),
  rewards: z.string().optional(),
});

type SeasonFormValues = z.infer<typeof seasonSchema>;

export default function AdminSeasonsPage() {
  const [seasons, setSeasons] = React.useState<Season[]>([]);
  const [loading, setLoading] = React.useState(true);
  const [dialogOpen, setDialogOpen] = React.useState(false);
  const [editingSeason, setEditingSeason] = React.useState<Season | null>(null);
  const [deleteDialog, setDeleteDialog] = React.useState<{
    open: boolean;
    id: string | null;
  }>({ open: false, id: null });

  const form = useForm<SeasonFormValues>({
    resolver: zodResolver(seasonSchema),
    defaultValues: {
      name: "",
      description: "",
      startDate: "",
      endDate: "",
      isActive: true,
      rewards: "",
    },
  });

  const fetchSeasons = React.useCallback(async () => {
    setLoading(true);
    try {
      const response = await fetch("/api/admin/seasons");
      const data = await response.json();
      setSeasons(data.seasons || []);
    } catch (error) {
      console.error("Error fetching seasons:", error);
      toast.error("حدث خطأ في استدعاء سجلات الملاحم");
    } finally {
      setLoading(false);
    }
  }, []);

  React.useEffect(() => {
    fetchSeasons();
  }, [fetchSeasons]);

  const handleOpenDialog = (season?: Season) => {
    if (season) {
      setEditingSeason(season);
      form.reset({
        name: season.name,
        description: season.description || "",
        startDate: season.startDate.split("T")[0],
        endDate: season.endDate.split("T")[0],
        isActive: season.isActive,
        rewards: season.rewards || "",
      });
    } else {
      setEditingSeason(null);
      form.reset({
        name: "",
        description: "",
        startDate: "",
        endDate: "",
        isActive: true,
        rewards: "",
      });
    }
    setDialogOpen(true);
  };

  const handleSubmit = async (values: SeasonFormValues) => {
    try {
      const url = "/api/admin/seasons";
      const method = editingSeason ? "PATCH" : "POST";
      const body = editingSeason ? { ...values, id: editingSeason.id } : values;

      const response = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body),
      });

      if (response.ok) {
        toast.success(editingSeason ? "تم تحديث قوانين الموسم" : "تم إعلان ملحمة جديدة في الإمبراطورية");
        setDialogOpen(false);
        fetchSeasons();
      } else {
        toast.error("فشل في حفظ الموسم");
      }
    } catch (error) {
      console.error("Error saving season:", error);
      toast.error("خطأ في الاتصال بالسجلات");
    }
  };

  const handleDelete = async () => {
    if (!deleteDialog.id) return;

    try {
      const response = await fetch("/api/admin/seasons", {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: deleteDialog.id }),
      });

      if (response.ok) {
        toast.success("تم مسح الموسم وحرق سجلاته");
        fetchSeasons();
      } else {
        toast.error("فشل في الإتلاف");
      }
    } catch (error) {
      console.error("Error deleting season:", error);
      toast.error("خطأ في الاتصال");
    } finally {
      setDeleteDialog({ open: false, id: null });
    }
  };

  const columns: ColumnDef<Season>[] = [
    {
      accessorKey: "name",
      header: "الموسم / الملحمة",
      cell: ({ row }) => {
        const season = row.original;
        return (
          <div className="flex items-center gap-4">
            <div className={`flex h-12 w-12 items-center justify-center rounded-[1rem] ${season.isActive ? "bg-purple-500/10 text-purple-500 shadow-[0_0_15px_rgba(168,85,247,0.2)]" : "bg-muted text-muted-foreground"} border border-white/10`}>
              <Crown className="h-6 w-6" />
            </div>
            <div>
              <p className="font-black text-sm tracking-tight">{season.name}</p>
              <p className="text-[10px] text-muted-foreground font-bold uppercase tracking-widest opacity-60 line-clamp-1 max-w-[200px]">
                {season.description || "لا يوجد وصف لهذا العصر"}
              </p>
            </div>
          </div>
        );
      },
    },
    {
      accessorKey: "isActive",
      header: "الحالة الملكية",
      cell: ({ row }) => {
        const active = row.original.isActive;
        return (
          <div className="flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full ${active ? "bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]" : "bg-red-500/30"}`} />
            <span className={`text-[10px] font-black uppercase tracking-widest ${active ? "text-emerald-500" : "text-muted-foreground"}`}>
              {active ? "حقبة نشطة" : "حقبة منتهية"}
            </span>
          </div>
        );
      },
    },
    {
      id: "duration",
      header: "الفترة الزمنية",
      cell: ({ row }) => (
        <div className="flex flex-col gap-1">
          <div className="flex items-center gap-1.5">
            <Calendar className="w-3 h-3 text-muted-foreground" />
            <span className="text-[10px] font-black">{new Date(row.original.startDate).toLocaleDateString("ar-EG")}</span>
          </div>
          <div className="flex items-center gap-1.5 opacity-50">
            <Timer className="w-3 h-3" />
            <span className="text-[10px] font-bold">{new Date(row.original.endDate).toLocaleDateString("ar-EG")}</span>
          </div>
        </div>
      ),
    },
    {
      id: "stats",
      header: "إحصائيات المعركة",
      cell: ({ row }) => (
        <div className="flex flex-col gap-1">
          <div className="flex items-center gap-2">
            <Swords className="w-3 h-3 text-orange-500" />
            <span className="text-[10px] font-black">{row.original._count?.participations || 0} محارب</span>
          </div>
          <div className="flex items-center gap-2 opacity-60">
            <Trophy className="w-3 h-3 text-yellow-500" />
            <span className="text-[10px] font-bold">{row.original._count?.leaderboards || 0} قائمة تصنيف</span>
          </div>
        </div>
      ),
    },
    {
      id: "actions",
      header: "التحكم الإمبراطوري",
      cell: ({ row }) => (
        <RowActions
          row={row.original}
          onEdit={handleOpenDialog}
          onDelete={(s) => setDeleteDialog({ open: true, id: s.id })}
          extraActions={[
            { 
              icon: Zap, 
              label: "تصفير الـ Leaderboard", 
              onClick: () => toast.success("تم إرسال أمر لإعادة تعيين موازين القوى وبدء حقبة جديدة.") 
            },
          ]}
        />
      ),
    },
  ];

  return (
    <div className="space-y-10 pb-20" dir="rtl">
      <PageHeader
        title="المواسم القتالية (Battle Passes) 🛡️"
        description="إدارة العصور التعليمية، ضبط جوائز الـ Battle Pass، وجدولة ملاحم القمة لجيش المحاربين."
      >
        <AdminButton 
          icon={Plus} 
          onClick={() => handleOpenDialog()}
          className="h-14 px-8 rounded-2xl text-md font-black shadow-xl bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700"
        >
          إعلان موسم جديد
        </AdminButton>
      </PageHeader>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <AdminStatsCard 
          title="عصور المملكة" 
          value={seasons.length} 
          icon={History} 
          color="blue"
          description="إجمالي المواسم المسجلة"
        />
        <AdminStatsCard 
          title="الحقبة الحالية" 
          value={seasons.filter(s => s.isActive).length} 
          icon={Flame} 
          color="red"
          description="مواسم نشطة الآن"
        />
        <AdminStatsCard 
          title="جيش المشاركين" 
          value={seasons.reduce((acc, s) => acc + (s._count?.participations || 0), 0)} 
          icon={Swords} 
          color="purple"
          description="إجمالي تداخل المحاربين"
        />
        <AdminStatsCard 
          title="جوائز مسلحة" 
          value={seasons.filter(s => s.rewards).length} 
          icon={Trophy} 
          color="yellow"
          description="مواسم بكنوز محددة"
        />
      </div>

      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="rpg-glass-light dark:rpg-glass p-1 rounded-[2.5rem] border border-white/10 overflow-hidden shadow-2xl"
      >
        {loading ? (
          <TableSkeleton rows={6} cols={5} />
        ) : (
          <AdminDataTable
            columns={columns}
            data={seasons}
            searchKey="name"
            searchPlaceholder="ابحث في سجلات الزمن..."
            actions={{ onRefresh: () => fetchSeasons() }}
          />
        )}
      </motion.div>

      {/* Add/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-lg bg-card/80 backdrop-blur-xl border-white/10 rounded-[2.5rem] p-0 overflow-hidden shadow-2xl">
          <div className="h-1.5 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500" />
          <div className="p-8">
            <DialogHeader className="mb-8">
              <DialogTitle className="text-2xl font-black flex items-center gap-3">
                {editingSeason ? (
                  <>
                    <Hammer className="w-7 h-7 text-indigo-500" />
                    تغيير معالم الحقبة
                  </>
                ) : (
                  <>
                    <Sparkles className="w-7 h-7 text-purple-500" />
                    إعلان عصر جديد
                  </>
                )}
              </DialogTitle>
              <DialogDescription className="font-bold text-muted-foreground">
                حدد ملامح الموسم القادم وأسس حجر الزاوية للمنافسة بين الأبطال.
              </DialogDescription>
            </DialogHeader>

            <Form {...form}>
              <form onSubmit={form.handleSubmit(handleSubmit)} className="space-y-6">
                <FormField
                  control={form.control}
                  name="name"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">اسـم الموسم</FormLabel>
                      <FormControl>
                        <Input {...field} placeholder="موسم فرسان النيل..." className="rounded-xl border-white/10 bg-white/5 h-12 px-6 font-bold" />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="description"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">تاريخ العصر (الوصف)</FormLabel>
                      <FormControl>
                        <Textarea {...field} placeholder="لقد بدأ زمن جديد..." className="rounded-2xl border-white/10 bg-white/5 p-4 min-h-[80px]" />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <div className="grid grid-cols-2 gap-4">
                  <FormField
                    control={form.control}
                    name="startDate"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">فجر الموسم (بداية)</FormLabel>
                        <FormControl>
                          <Input {...field} type="date" className="rounded-xl border-white/10 bg-white/5 h-11 px-4 font-bold" />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="endDate"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">غروب الموسم (نهاية)</FormLabel>
                        <FormControl>
                          <Input {...field} type="date" className="rounded-xl border-white/10 bg-white/5 h-11 px-4 font-bold" />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>

                <FormField
                  control={form.control}
                  name="rewards"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">مخطط الغنائم (Rewards Path)</FormLabel>
                      <FormControl>
                        <Textarea {...field} placeholder="المستوى 1: وسام، المستوى 5: لقب..." className="rounded-2xl border-white/10 bg-white/5 p-4 min-h-[80px]" />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="isActive"
                  render={({ field }) => (
                    <FormItem className="flex items-center justify-between rounded-xl border border-white/10 p-4 bg-white/5 shadow-inner">
                      <div className="space-y-0.5">
                        <FormLabel className="font-black text-xs">تفعيل الحقبة الآن؟</FormLabel>
                        <p className="text-[10px] text-muted-foreground font-bold uppercase">سيظهر الموسم فوراً لكافة المحاربين</p>
                      </div>
                      <FormControl>
                        <Switch
                          checked={field.value}
                          onCheckedChange={field.onChange}
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />

                <DialogFooter className="pt-4">
                  <AdminButton type="submit" icon={editingSeason ? Hammer : Sparkles} className="w-full h-14 text-md font-black shadow-xl rounded-2xl">
                    {editingSeason ? "تحديث ميثاق الموسم" : "إعلان الموسم في الإمبراطورية"}
                  </AdminButton>
                </DialogFooter>
              </form>
            </Form>
          </div>
        </DialogContent>
      </Dialog>

      <ConfirmDialog
        open={deleteDialog.open}
        onOpenChange={(open) => setDeleteDialog({ open, id: null })}
        title="إتلاف الموسم نهائياً؟"
        description="أنت على وشك حرق سجلات هذا الموسم من تاريخ المملكة. هل أنت متأكد؟"
        confirmText="نعم، احذف الموسم"
        variant="destructive"
        onConfirm={handleDelete}
      />
    </div>
  );
}

"use client";

import * as React from "react";
import { PageHeader } from "@/components/admin/ui/page-header";
import { AdminDataTable, RowActions } from "@/components/admin/ui/admin-table";
import { AdminButton } from "@/components/admin/ui/admin-button";
import { AdminCard } from "@/components/admin/ui/admin-card";
import { 
  Plus, GraduationCap, Globe, MessageCircle, Star, Users, School, Search
} from "lucide-react";
import { ColumnDef } from "@tanstack/react-table";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { toast } from "sonner";
import { ConfirmDialog } from "@/components/admin/ui/confirm-dialog";
import { 
  Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle 
} from "@/components/ui/dialog";
import { 
  Form, FormControl, FormField, FormItem, FormLabel, FormMessage 
} from "@/components/ui/form";
import { 
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue 
} from "@/components/ui/select";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { useQuery } from "@tanstack/react-query";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";

interface Teacher {
  id: string;
  name: string;
  subjectId: string;
  onlineUrl: string | null;
  rating: number;
  notes: string | null;
  createdAt: string;
  subject: {
    name: string;
    nameAr: string | null;
    color: string | null;
  };
}

interface TeachersResponse {
  data: {
    teachers: Teacher[];
  };
}

interface SubjectsListResponse {
  data: {
    subjects: Array<{ id: string; name: string; nameAr: string | null }>;
  };
}

const teacherSchema = z.object({
  name: z.string().min(1, "اسم المعلم مطلوب"),
  subjectId: z.string().min(1, "المادة الدراسية مطلوبة"),
  onlineUrl: z.string().url("يجب أن يكون رابطاً صحيحاً").or(z.literal("")),
  notes: z.string().optional(),
});

type TeacherFormValues = z.infer<typeof teacherSchema>;

export default function AdminTeachersPage() {
  const [dialogOpen, setDialogOpen] = React.useState(false);
  const [editingTeacher, setEditingTeacher] = React.useState<Teacher | null>(null);
  const [deleteDialog, setDeleteDialog] = React.useState<{ open: boolean; id: string | null }>({
    open: false,
    id: null,
  });
  const [search, setSearch] = React.useState("");
  const deferredSearch = React.useDeferredValue(search);

  const { data, isLoading, refetch } = useQuery({
    queryKey: ["admin", "teachers"],
    queryFn: async () => {
      const response = await fetch("/api/admin/teachers");
      return (await response.json()) as TeachersResponse;
    },
  });

  const { data: subjects = [] } = useQuery({
    queryKey: ["admin", "subjects-list"],
    queryFn: async () => {
      const response = await fetch("/api/admin/subjects?limit=100");
      const result = (await response.json()) as SubjectsListResponse;
      return result.data?.subjects || [];
    },
  });

  const teachers = React.useMemo(() => {
    const items = data?.data?.teachers || [];
    if (!deferredSearch) {
      return items;
    }

    const query = deferredSearch.toLowerCase();
    return items.filter((teacher) =>
      teacher.name.toLowerCase().includes(query) ||
      teacher.subject.name.toLowerCase().includes(query) ||
      (teacher.subject.nameAr || "").toLowerCase().includes(query)
    );
  }, [data, deferredSearch]);

  const form = useForm<TeacherFormValues>({
    resolver: zodResolver(teacherSchema),
    defaultValues: {
      name: "",
      subjectId: "",
      onlineUrl: "",
      notes: "",
    },
  });

  const handleOpenDialog = (teacher?: Teacher) => {
    if (teacher) {
      setEditingTeacher(teacher);
      form.reset({
        name: teacher.name,
        subjectId: teacher.subjectId,
        onlineUrl: teacher.onlineUrl || "",
        notes: teacher.notes || "",
      });
    } else {
      setEditingTeacher(null);
      form.reset({
        name: "",
        subjectId: "",
        onlineUrl: "",
        notes: "",
      });
    }
    setDialogOpen(true);
  };

  const handleSubmit = async (values: TeacherFormValues) => {
    try {
      const method = editingTeacher ? "PATCH" : "POST";
      const body = editingTeacher ? { ...values, id: editingTeacher.id } : values;
      const response = await fetch("/api/admin/teachers", {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body),
      });

      if (response.ok) {
        toast.success(editingTeacher ? "تم تحديث رتبة المعلم" : "تم تعيين قائد علمي جديد");
        setDialogOpen(false);
        refetch();
      } else {
        toast.error("فشل في حفظ بيانات المعلم");
      }
    } catch (_error) {
      toast.error("خطأ في الاتصال");
    }
  };

  const handleDelete = async () => {
    if (!deleteDialog.id) return;
    try {
      const response = await fetch("/api/admin/teachers", {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id: deleteDialog.id }),
      });

      if (response.ok) {
        toast.success("تم عزل المعلم من هيئة التدريس");
        refetch();
      } else {
        toast.error("فشل في العزل");
      }
    } catch (_error) {
      toast.error("خطأ في الاتصال");
    } finally {
      setDeleteDialog({ open: false, id: null });
    }
  };

  const columns: ColumnDef<Teacher>[] = [
    {
      accessorKey: "name",
      header: "القائد العلمي",
      cell: ({ row }) => {
        const teacher = row.original;
        return (
          <div className="flex items-center gap-4">
            <Avatar className="h-12 w-12 border-2 border-primary/20 shadow-xl p-0.5 bg-background overflow-hidden rounded-[1rem]">
              <AvatarImage src={`https://api.dicebear.com/7.x/notionists/svg?seed=${teacher.name}`} />
              <AvatarFallback className="font-black bg-primary/10 text-primary uppercase">{teacher.name.substring(0, 2)}</AvatarFallback>
            </Avatar>
            <div>
              <p className="font-black text-sm tracking-tight">{teacher.name}</p>
              <div className="flex items-center gap-1.5 mt-0.5">
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)]"></div>
                <span className="text-[10px] text-muted-foreground font-bold uppercase tracking-wider">رتبة: أستاذ قدير</span>
              </div>
            </div>
          </div>
        );
      },
    },
    {
      accessorKey: "subject",
      header: "العلم المختص",
      cell: ({ row }) => {
        const subject = row.original.subject;
        return (
          <Badge 
            variant="outline" 
            className="font-black text-[10px] uppercase tracking-wider rounded-lg border-2 px-3 py-1 shadow-sm" 
            style={{ 
              borderColor: subject.color ? `${subject.color}40` : "#3b82f640",
              color: subject.color || "#3b82f6",
              backgroundColor: subject.color ? `${subject.color}10` : "#3b82f610"
            }}
          >
            {subject.nameAr || subject.name}
          </Badge>
        );
      },
    },
    {
      accessorKey: "rating",
      header: "الثقة الملكية",
      cell: ({ row }) => (
        <div className="flex items-center gap-2">
          <div className="flex -space-x-1">
            {[1, 2, 3, 4, 5].map((s) => (
              <Star 
                key={s} 
                className={`w-3.5 h-3.5 ${s <= Math.round(row.original.rating) ? "text-amber-500 fill-current" : "text-muted opacity-20"}`} 
              />
            ))}
          </div>
          <span className="text-xs font-black">{row.original.rating.toFixed(1)}</span>
        </div>
      ),
    },
    {
      accessorKey: "onlineUrl",
      header: "منصة التواصل",
      cell: ({ row }) => {
        const url = row.original.onlineUrl;
        if (!url) return <span className="text-[10px] font-bold opacity-30 italic">لا يوجد رابط</span>;
        return (
          <AdminButton
            icon={Globe}
            variant="ghost"
            size="sm"
            className="text-primary hover:bg-primary/5 h-8 px-3 gap-2 border-none"
            onClick={() => window.open(url || "", "_blank")}
          >
            <span className="text-[10px] font-black uppercase">زيارة المقر</span>
          </AdminButton>
        );
      },
    },
    {
      id: "actions",
      header: "التحكم",
      cell: ({ row }) => (
        <RowActions
          row={row.original}
          onEdit={handleOpenDialog}
          onDelete={(t) => setDeleteDialog({ open: true, id: t.id })}
          extraActions={[
            { icon: MessageCircle, label: "إرسال رسالة ملكية", onClick: (t) => toast.info(`قريباً: التواصل مع ${t.name}`) },
          ]}
        />
      ),
    },
  ];

  return (
    <div className="space-y-10 pb-20" dir="rtl">
      <PageHeader
        title="مجلس الحكماء والعلماء 🎓"
        description="إدارة هيئة التدريس، تخصصات المعلمين، وقنوات التواصل المباشرة مع الطلاب."
      >
        <AdminButton icon={Plus} onClick={() => handleOpenDialog()}>
          تعيين قائد جديد
        </AdminButton>
      </PageHeader>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {[
          { label: "كبار العلماء", value: teachers.length, icon: GraduationCap, color: "blue" },
          { label: "متوسط الثقة", value: (teachers.reduce((acc, t) => acc + t.rating, 0) / (teachers.length || 1)).toFixed(1), icon: Star, color: "amber" },
          { label: "تخصصات علمية", value: Array.from(new Set(teachers.map(t => t.subjectId))).length, icon: School, color: "purple" },
          { label: "قادة جدد", value: teachers.filter(t => new Date(t.createdAt).getFullYear() === 2024).length, icon: Users, color: "emerald" },
        ].map((stat, i) => (
          <AdminCard key={i} variant="glass" className={`p-6 bg-${stat.color}-500/5 border-${stat.color}-500/10`}>
            <div className="flex items-center gap-4">
              <div className={`p-3 rounded-2xl bg-${stat.color}-500/10 text-${stat.color}-500`}>
                <stat.icon className="w-6 h-6" />
              </div>
              <div>
                <p className="text-2xl font-black">{stat.value}</p>
                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">{stat.label}</p>
              </div>
            </div>
          </AdminCard>
        ))}
      </div>

      <AdminDataTable
        columns={columns}
        data={teachers}
        loading={isLoading}
        actions={{ onRefresh: () => refetch() }}
      />

      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-md bg-card/80 backdrop-blur-xl border-white/10 rounded-[2.5rem] p-0 overflow-hidden">
          <div className="h-1.5 bg-gradient-to-r from-primary to-blue-500" />
          <div className="p-8">
            <DialogHeader className="mb-8">
              <DialogTitle className="text-2xl font-black">
                {editingTeacher ? "تعديل بيانات الحكيم" : "تعيين معلم جديد"}
              </DialogTitle>
              <DialogDescription className="font-bold text-muted-foreground">
                يرجى إدخال بيانات القائد العلمي بدقة لضمان تواصل فعال مع المحاربين.
              </DialogDescription>
            </DialogHeader>
            <Form {...form}>
              <form onSubmit={form.handleSubmit(handleSubmit)} className="space-y-6">
                <FormField
                  control={form.control}
                  name="name"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">الاسم الكامل للقائد</FormLabel>
                      <FormControl><Input {...field} placeholder="الاسم ثلاثي أو رباعي" className="rounded-2xl border-white/10 bg-white/5 h-12 px-6 focus:ring-1 ring-primary/50" /></FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="subjectId"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">التخصص الدراسي</FormLabel>
                      <Select value={field.value} onValueChange={field.onChange}>
                        <FormControl>
                          <SelectTrigger className="rounded-2xl border-white/10 bg-white/5 h-12 px-6">
                            <SelectValue placeholder="اختر المادة العلمية" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent className="rounded-2xl border-white/10">
                          {subjects.map((subject: any) => (
                            <SelectItem key={subject.id} value={subject.id} className="cursor-pointer py-3">
                              {subject.nameAr || subject.name}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="onlineUrl"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">رابط القناة الرسمية (URL)</FormLabel>
                      <FormControl><Input {...field} dir="ltr" placeholder="https://..." className="rounded-2xl border-white/10 bg-blue-500/5 text-blue-400 h-12 px-6" /></FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="notes"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="font-black text-[10px] uppercase tracking-widest opacity-60">توصيات ملكية (ملاحظات)</FormLabel>
                      <FormControl><Textarea {...field} className="rounded-2xl border-white/10 bg-white/5 min-h-[100px] p-6 focus:ring-1 ring-primary/50" /></FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <DialogFooter className="pt-4">
                  <AdminButton type="submit" className="w-full h-14 text-md font-black shadow-xl">
                    {editingTeacher ? "حفظ المرسوم الملكي" : "اعتماد القائد رسمياً"}
                  </AdminButton>
                </DialogFooter>
              </form>
            </Form>
          </div>
        </DialogContent>
      </Dialog>

      <ConfirmDialog
        open={deleteDialog.open}
        onOpenChange={(open) => setDeleteDialog({ open, id: null })}
        title="تأكيد العزل النهائي؟"
        description="أنت على وشك عزل هذا القائد العلمي من هيئة التدريس بالمملكة. هل أنت متأكد من هذا القرار؟"
        confirmText="نعم، اعزله"
        variant="destructive"
        onConfirm={handleDelete}
      />
    </div>
  );
}

"use client";

import * as React from "react";
import { PageHeader } from "@/components/admin/ui/page-header";
import { AdminDataTable } from "@/components/admin/ui/admin-table";
import { AdminCard } from "@/components/admin/ui/admin-card";
import { AdminButton } from "@/components/admin/ui/admin-button";
import { 
  Shield, ShieldAlert, ShieldCheck, UserCog, Save, RotateCcw
} from "lucide-react";
import { ColumnDef } from "@tanstack/react-table";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { PERMISSIONS, DEFAULT_ROLE_PERMISSIONS, Permission } from "@/lib/permissions";
import { UserRole } from "@prisma/client";
import { toast } from "sonner";

import { Badge } from "@/components/ui/badge";
import { Switch } from "@/components/ui/switch";
import { 
  Tooltip, TooltipContent, TooltipProvider, TooltipTrigger 
} from "@/components/ui/tooltip";
import { 
  Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle 
} from "@/components/ui/dialog";

interface User {
  id: string;
  name: string;
  email: string;
  role: string;
  permissions: string[];
}

export default function PermissionsPage() {
  const queryClient = useQueryClient();
  const [selectedUser, setSelectedUser] = React.useState<User | null>(null);
  const [editingPermissions, setEditingPermissions] = React.useState<string[]>([]);
  const [isDialogOpen, setIsDialogOpen] = React.useState(false);

  const { data: usersData, isLoading } = useQuery({
    queryKey: ["admin", "staff-users"],
    queryFn: async () => {
      const res = await fetch("/api/admin/users?role=ADMIN&limit=100"); // Getting Admins for now, will filter/add others
      const admins = await res.json();

      const res2 = await fetch("/api/admin/users?role=TEACHER&limit=100");
      const teachers = await res2.json();

      const res3 = await fetch("/api/admin/users?role=MODERATOR&limit=100");
      const moderators = await res3.json();

      return [
        ...(admins.data?.users || []),
        ...(teachers.data?.users || []),
        ...(moderators.data?.users || [])
      ] as User[];
    }
  });

  const updatePermissionsMutation = useMutation({
    mutationFn: async ({ userId, permissions }: { userId: string, permissions: string[] }) => {
      const res = await fetch("/api/admin/users", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ userId, permissions }),
      });
      if (!res.ok) throw new Error("Failed to update permissions");
      return res.json();
    },
    onSuccess: () => {
      toast.success("تم تحديث صلاحيات المحارب بنجاح!");
      queryClient.invalidateQueries({ queryKey: ["admin", "staff-users"] });
      setIsDialogOpen(false);
    },
    onError: () => toast.error("فشل في تحديث الصلاحيات")
  });

  const handleEditPermissions = (user: User) => {
    setSelectedUser(user);
    setEditingPermissions(user.permissions || []);
    setIsDialogOpen(true);
  };

  const togglePermission = (perm: string) => {
    setEditingPermissions(prev => 
      prev.includes(perm) ? prev.filter(p => p !== perm) : [...prev, perm]
    );
  };

  const columns: ColumnDef<User>[] = [
    {
      accessorKey: "name",
      header: "المحارب",
      cell: ({ row }) => (
        <div className="flex flex-col">
          <span className="font-black text-sm">{row.original.name}</span>
          <span className="text-[10px] text-muted-foreground">{row.original.email}</span>
        </div>
      )
    },
    {
      accessorKey: "role",
      header: "الرتبة العسكرية",
      cell: ({ row }) => {
        const role = row.original.role;
        const colors: Record<string, string> = {
          ADMIN: "bg-red-500/10 text-red-500 border-red-500/20",
          TEACHER: "bg-blue-500/10 text-blue-500 border-blue-500/20",
          MODERATOR: "bg-emerald-500/10 text-emerald-500 border-emerald-500/20",
        };
        const labels: Record<string, string> = {
          ADMIN: "قائد أعلى",
          TEACHER: "قائد كتيبة",
          MODERATOR: "مراقب ملكي",
        };
        return (
          <Badge className={`rounded-full px-3 py-0.5 text-[10px] font-black uppercase ${colors[role] || ""}`}>
            {labels[role] || role}
          </Badge>
        );
      }
    },
    {
      accessorKey: "permissions",
      header: "الصلاحيات النشطة",
      cell: ({ row }) => (
        <div className="flex flex-wrap gap-1">
          <Badge variant="outline" className="text-[10px] border-white/5 opacity-60">
            {row.original.permissions?.length || 0} استثناءات
          </Badge>
          {row.original.role === "ADMIN" && (
            <Badge className="bg-amber-500/10 text-amber-500 text-[10px] font-bold border-none">كل الصلاحيات (Admin Override)</Badge>
          )}
        </div>
      )
    },
    {
      id: "actions",
      header: "إدارة",
      cell: ({ row }) => (
        <AdminButton 
          size="sm" 
          variant="outline" 
          icon={ShieldCheck} 
          onClick={() => handleEditPermissions(row.original)}
          className="rounded-xl h-8 text-[10px] font-black"
        >
          تعديل الصلاحيات
        </AdminButton>
      )
    }
  ];

  const permissionCategories = React.useMemo(() => {
    const categories: Record<string, string[]> = {
      "الإدارة": ["dashboard:view", "analytics:view", "reports:view", "settings:view", "audit_logs:view"],
      "المستخدمين": ["users:view", "users:manage", "students:view", "teachers:view", "teachers:manage"],
      "المحتوى": ["subjects:view", "subjects:manage", "own_subjects:manage", "books:view", "books:manage", "own_books:manage", "resources:view", "resources:manage"],
      "التعليم": ["exams:view", "exams:manage", "own_exams:manage", "challenges:view", "challenges:manage", "own_challenges:manage", "contests:view", "contests:manage"],
      "المجتمع": ["blog:view", "blog:manage", "forum:view", "forum:moderate", "forum:manage", "comments:view", "comments:moderate", "events:view", "events:manage", "announcements:view", "announcements:manage"],
      "أخرى": ["achievements:view", "achievements:manage", "rewards:view", "rewards:manage", "ai:manage", "live_monitor:view", "marketing:view", "ab_testing:view"]
    };
    return categories;
  }, []);

  return (
    <div className="space-y-10 pb-20" dir="rtl">
      <PageHeader 
        title="مصفوفة الصلاحيات (Kingdom Guard) ⚔️"
        description="إدارة رتب الأبطال والقادة، منح وتجريد الصلاحيات من القادة والمراقبين."
      >
        <AdminButton icon={ShieldAlert} variant="outline" className="opacity-70 group hover:opacity-100">
           إعادة تعيين كافة الرتب
        </AdminButton>
      </PageHeader>

      <AdminDataTable 
        columns={columns}
        data={usersData || []}
        loading={isLoading}
        searchKey="name"
        searchPlaceholder="ابحث عن قائد أو مراقب..."
      />

      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className="max-w-5xl bg-card/90 backdrop-blur-2xl border-white/10 rounded-[2.5rem] overflow-hidden p-0 h-[85vh] flex flex-col">
          <DialogHeader className="p-8 border-b border-white/5 shrink-0" dir="rtl">
            <div className="flex items-center gap-6">
               <div className="w-16 h-16 rounded-3xl bg-primary/10 flex items-center justify-center text-primary">
                  <UserCog className="w-8 h-8" />
               </div>
               <div>
                  <DialogTitle className="text-2xl font-black">إدارة صلاحيات: {selectedUser?.name}</DialogTitle>
                  <DialogDescription className="font-bold">يمكنك تخصيص الصلاحيات لهذا المحارب بشكل فردي فوق صلاحياته الافتراضية.</DialogDescription>
               </div>
            </div>
          </DialogHeader>

          <div className="flex-1 overflow-y-auto p-8 bg-white/[0.02]" dir="rtl">
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                <TooltipProvider>
                {Object.entries(permissionCategories).map(([cat, perms]) => (
                   <div key={cat} className="space-y-4">
                      <h4 className="text-xs font-black uppercase tracking-[0.2em] text-muted-foreground border-b border-white/5 pb-2 mb-4">{cat}</h4>
                      <div className="space-y-3">
                         {perms.map(p => {
                            const isDefault = selectedUser ? (DEFAULT_ROLE_PERMISSIONS[selectedUser.role as UserRole] || []).includes(p as Permission) : false;
                            const isActive = editingPermissions.includes(p) || isDefault;

                            const isOverride = editingPermissions.includes(p);

                            return (
                               <div key={p} className={`flex items-center justify-between p-3 rounded-2xl border transition-all ${isActive ? 'bg-primary/5 border-primary/20' : 'bg-transparent border-white/5 opacity-50'}`}>
                                  <div className="space-y-0.5">
                                     <p className="text-[10px] font-black uppercase tracking-tight">{p.replace(/:/g, ' ')}</p>
                                     {isDefault && <Badge className="bg-emerald-500/10 text-emerald-500 text-[8px] font-black border-none uppercase h-4">افتراضي (Role)</Badge>}
                                     {isOverride && !isDefault && <Badge className="bg-amber-500/10 text-amber-500 text-[8px] font-black border-none uppercase h-4">استثناء (User)</Badge>}
                                  </div>

                                  <Switch 
                                    checked={isActive}
                                    disabled={isDefault}
                                    onCheckedChange={() => togglePermission(p)}
                                    title={isDefault ? "هذه الصلاحية تأتي تلقائياً مع الرتبة" : ""}
                                  />
                               </div>
                            );
                         })}
                      </div>
                   </div>
                ))}
                </TooltipProvider>
             </div>
          </div>

          <DialogFooter className="p-8 border-t border-white/5 bg-background shrink-0" dir="rtl">
             <div className="flex items-center gap-3 w-full">
                <AdminButton 
                  className="flex-1 h-14 rounded-2xl text-lg font-black gap-3"
                  icon={Save}
                  onClick={() => selectedUser && updatePermissionsMutation.mutate({ userId: selectedUser.id, permissions: editingPermissions })}
                  loading={updatePermissionsMutation.isPending}
                >
                  حفظ الصلاحيات الملكية 🏛️
                </AdminButton>
                <AdminButton 
                  variant="outline" 
                  className="h-14 w-14 rounded-2xl border-white/10"
                  icon={RotateCcw}
                  onClick={() => setSelectedUser(null)}
                />
             </div>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { PageHeader } from "@/components/admin/ui/page-header";
import { AdminCard } from "@/components/admin/ui/admin-card";
import { AdminButton } from "@/components/admin/ui/admin-button";
import { 
  Ticket, 
  Plus, 
  Trash2, 
  CheckCircle2, 
  XCircle, 
  Search, 
  Calendar, 
  Percent, 
  Activity,
  TrendingUp,
  Settings,
  RefreshCw
} from "lucide-react";
import { toast } from "sonner";
import { format } from "date-fns";
import { ar } from "date-fns/locale";

interface Coupon {
  id: string;
  code: string;
  description: string | null;
  discountType: "PERCENTAGE" | "FIXED";
  discountValue: number;
  maxUses: number | null;
  usedCount: number;
  expiryDate: string | null;
  isActive: boolean;
  minOrderAmount: number;
  createdAt: string;
  _count?: {
      payments: number;
  };
}

export default function AdminCouponsPage() {
  const [coupons, setCoupons] = useState<Coupon[]>([]);
  const [loading, setLoading] = useState(true);
  const [isAdding, setIsAdding] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [activeFilter, setActiveFilter] = useState<"all" | "active" | "inactive">("all");

  // Form State
  const [newCoupon, setNewCoupon] = useState({
    code: "",
    discountType: "PERCENTAGE" as "PERCENTAGE" | "FIXED",
    discountValue: "",
    description: "",
    maxUses: "",
    expiryDate: "",
    minOrderAmount: "",
  });

  const fetchCoupons = async () => {
    try {
      const res = await fetch("/api/admin/coupons");
      if (res.ok) {
        const data = await res.json();
        setCoupons(data);
      }
    } catch (_err) {
      toast.error("خطأ في جلب الأكواد");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCoupons();
  }, []);

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newCoupon.code || !newCoupon.discountValue) {
        return toast.error("يرجى إكمال البيانات الأساسية");
    }

    try {
      const res = await fetch("/api/admin/coupons", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newCoupon),
      });

      if (res.ok) {
        toast.success("تم إنشاء الكود بنجاح!");
        fetchCoupons();
        setIsAdding(false);
        setNewCoupon({
            code: "",
            discountType: "PERCENTAGE",
            discountValue: "",
            description: "",
            maxUses: "",
            expiryDate: "",
            minOrderAmount: "",
        });
      } else {
          const data = await res.json();
          toast.error(data.error || "فشل إنشاء الكود");
      }
    } catch (_err) {
      toast.error("حدث خطأ غير متوقع");
    }
  };

  const toggleStatus = async (id: string, current: boolean) => {
    try {
      const res = await fetch(`/api/admin/coupons/${id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ isActive: !current }),
      });
      if (res.ok) {
        toast.success("تم تحديث الحالة");
        fetchCoupons();
      }
    } catch (_err) {
      toast.error("فشل التحديث");
    }
  };

  const deleteCoupon = async (id: string) => {
    if (!confirm("هل أنت متأكد من حذف هذا الكود؟ لا يمكن التراجع!")) return;
    try {
        const res = await fetch(`/api/admin/coupons/${id}`, { method: "DELETE" });
        if (res.ok) {
            toast.success("تم حذف الكود");
            fetchCoupons();
        }
    } catch (_err) {
        toast.error("فشل الحذف");
    }
  };

  const filtered = coupons.filter(c => {
    const matchesSearch = c.code.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesFilter = activeFilter === "all" || (activeFilter === "active" ? c.isActive : !c.isActive);
    return matchesSearch && matchesFilter;
  });

  const stats = {
      total: coupons.length,
      active: coupons.filter(c => c.isActive).length,
      totalUses: coupons.reduce((sum, c) => sum + (c._count?.payments || c.usedCount), 0),
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center">Loading...</div>;

  return (
    <div className="min-h-screen bg-[#0a0a0c] text-white p-8 font-inter" dir="rtl">
