           </div>
           <div className="bg-[#111114] border border-white/5 p-6 rounded-2xl flex items-center gap-6">
               <div className="w-12 h-12 rounded-xl bg-green-500/10 flex items-center justify-center text-green-500">
                   <Activity size={24} />
