'use client';

import { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  History, 
  Search, 
  Filter, 
  Download, 
  Info, 
  CheckCircle2, 
  AlertTriangle, 
  XCircle, 
  ChevronDown, 
  ChevronUp,
  MapPin,
  Clock,
  Smartphone,
  Shield,
  Loader2,
  ArrowRight
} from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';
import { ar } from 'date-fns/locale';
import Link from 'next/link';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';

interface SecurityLog {
  id: string;
  eventType: string;
  ip: string;
  userAgent: string;
  location: string | null;
  createdAt: string;
  metadata: string | null;
}

const EVENT_LABELS: Record<string, { label: string; color: string; icon: any }> = {
  LOGIN_SUCCESS: { label: 'تسجيل دخول ناجح', color: 'text-green-400', icon: CheckCircle2 },
  LOGIN_FAILED: { label: 'محاولة دخول فاشلة', color: 'text-red-400', icon: XCircle },
  LOGOUT: { label: 'تسجيل خروج', color: 'text-slate-400', icon: Info },
  REGISTER: { label: 'إنشاء حساب جديد', color: 'text-indigo-400', icon: CheckCircle2 },
  PASSWORD_CHANGE: { label: 'تغيير كلمة المرور', color: 'text-yellow-400', icon: AlertTriangle },
  MAGIC_LINK_REQUESTED: { label: 'طلب رابط دخول', color: 'text-purple-400', icon: History },
  DEVICE_TRUST_CHANGE: { label: 'تغيير حالة ثقة الجهاز', color: 'text-orange-400', icon: Shield },
  SUSPICIOUS_ACTIVITY: { label: 'نشاط مشبوه', color: 'text-red-500', icon: AlertTriangle },
};

export default function SecurityLogsPage() {
  const [logs, setLogs] = useState<SecurityLog[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [filter, setFilter] = useState('');

  const fetchLogs = useCallback(async () => {
    setIsLoading(true);
    try {
      const res = await fetch('/api/auth/security-logs?limit=50');
      if (!res.ok) throw new Error('Failed to fetch logs');
      const data = await res.json();
      setLogs(data.logs || []);
    } catch (error) {
      toast.error('فشل تحميل سجل النشاطات');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchLogs();
  }, [fetchLogs]);

  const filteredLogs = logs.filter(log => 
    EVENT_LABELS[log.eventType]?.label.includes(filter) || 
    log.ip.includes(filter) || 
    (log.location || '').includes(filter)
  );

  // Export logs to CSV
  const handleExportLogs = useCallback(() => {
    if (filteredLogs.length === 0) {
      toast.error('لا توجد سجلات للتصدير');
      return;
    }

    const headers = ['التاريخ', 'الحدث', 'IP', 'الموقع', 'User Agent', 'بيانات إضافية'];
    const rows = filteredLogs.map(log => [
      new Date(log.createdAt).toLocaleString('ar-EG'),
      EVENT_LABELS[log.eventType]?.label || log.eventType,
      log.ip,
      log.location || 'غير معروف',
      log.userAgent,
      log.metadata || ''
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.map(cell => `"${cell}"`).join(','))
    ].join('\n');

    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `security-logs-${new Date().toISOString().split('T')[0]}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
    
    toast.success('تم تصدير السجل بنجاح');
  }, [filteredLogs]);

  return (
    <div className="max-w-5xl mx-auto space-y-8 p-4">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <Link 
            href="/settings/security" 
            className="text-xs text-indigo-400 hover:text-indigo-300 flex items-center gap-1 mb-2 transition-colors"
          >
            <ArrowRight className="h-3 w-3 rotate-180" />
            العودة لصفحة الأمان
          </Link>
          <h1 className="text-2xl font-bold text-white flex items-center gap-3">
            <History className="h-7 w-7 text-indigo-400" />
            سجل النشاطات الأمنية
          </h1>
          <p className="text-sm text-slate-400 mt-1">سجل كامل لجميع العمليات الحساسة المرتبطة بحسابك</p>
        </div>

        <button 
          onClick={handleExportLogs} 
          className="flex items-center gap-2 px-4 py-2 rounded-xl bg-white/5 border border-white/10 text-white hover:bg-white/10 transition-colors text-sm"
        >
          <Download className="h-4 w-4" />
          تصدير السجل
        </button>
      </div>

      {/* Toolbar */}
      <div className="flex flex-col sm:flex-row gap-4 items-center">
        <div className="relative flex-1 w-full">
          <Search className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-500" />
          <input
            type="text"
            placeholder="بحث في السجل..."
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
            className="w-full pl-4 pr-10 py-2.5 rounded-xl bg-white/5 border border-white/10 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all text-sm"
          />
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          <button className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl bg-white/5 border border-white/10 text-slate-300 hover:text-white transition-colors text-sm">
            <Filter className="h-4 w-4" />
            تصفية
          </button>
        </div>
      </div>

      {/* Logs Table/List */}
      <div className="rounded-2xl border border-white/10 bg-slate-900/50 overflow-hidden">
        {isLoading ? (
          <div className="flex flex-col items-center justify-center py-20 gap-4">
            <Loader2 className="h-8 w-8 text-indigo-500 animate-spin" />
            <p className="text-slate-400 animate-pulse">جاري تحميل السجل...</p>
          </div>
        ) : filteredLogs.length > 0 ? (
          <div className="divide-y divide-white/5">
            {filteredLogs.map((log) => {
              const EventIcon = EVENT_LABELS[log.eventType]?.icon || Info;
              const isExpanded = expandedId === log.id;
              
              return (
                <div key={log.id} className="group transition-colors hover:bg-white/[0.02]">
                  <div 
                    className="p-4 sm:p-6 flex items-start gap-4 cursor-pointer"
                    onClick={() => setExpandedId(isExpanded ? null : log.id)}
                  >
                    <div className={cn(
                      "mt-1 p-2 rounded-lg bg-white/5 transition-colors",
                      EVENT_LABELS[log.eventType]?.color
                    )}>
                      <EventIcon className="h-5 w-5" />
                    </div>
                    
                    <div className="flex-1 min-w-0">
                      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-2 mb-1">
                        <span className={cn("font-medium truncate", EVENT_LABELS[log.eventType]?.color)}>
                          {EVENT_LABELS[log.eventType]?.label || log.eventType}
                        </span>
                        <span className="text-xs text-slate-500 flex items-center gap-1">
                          <Clock className="h-3 w-3" />
                          {formatDistanceToNow(new Date(log.createdAt), { addSuffix: true, locale: ar })}
                        </span>
                      </div>
                      
                      <div className="flex flex-wrap items-center gap-x-4 gap-y-1 text-xs text-slate-400">
                        <span className="flex items-center gap-1">
                          <MapPin className="h-3 w-3" />
                          {log.location || 'غير معروف'}
                        </span>
                        <span className="flex items-center gap-1">
                          <Shield className="h-3 w-3" />
                          {log.ip}
                        </span>
                        <span className="flex items-center gap-1">
                          <Smartphone className="h-3 w-3" />
                          {log.userAgent.split(' ')[0]}
                        </span>
                      </div>
                    </div>

                    <div className="mt-1">
                      {isExpanded ? <ChevronUp className="h-5 w-5 text-slate-600" /> : <ChevronDown className="h-5 w-5 text-slate-600" />}
                    </div>
                  </div>

                  <AnimatePresence>
                    {isExpanded && (
                      <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        className="overflow-hidden bg-white/[0.01]"
                      >
                        <div className="px-6 pb-6 pt-2 border-t border-white/5">
                          <div className="grid sm:grid-cols-2 gap-6 mt-4">
                            <div className="space-y-3">
                              <h4 className="text-xs font-bold text-slate-500 uppercase tracking-widest">تفاصيل الطلب</h4>
                              <div className="p-3 rounded-xl bg-black/20 border border-white/5 space-y-2">
                                <p className="text-xs text-slate-400 flex justify-between">
                                  <span>كامل User Agent:</span>
                                  <span className="text-slate-200 truncate max-w-[200px]" title={log.userAgent}>{log.userAgent}</span>
                                </p>
                                <p className="text-xs text-slate-400 flex justify-between">
                                  <span>معرف IP:</span>
                                  <span className="text-slate-200 font-mono tracking-tighter">{log.ip}</span>
                                </p>
                                <p className="text-xs text-slate-400 flex justify-between">
                                  <span>الوقت الدقيق:</span>
                                  <span className="text-slate-200">{new Date(log.createdAt).toLocaleString('ar-EG')}</span>
                                </p>
                              </div>
                            </div>
                            <div className="space-y-3">
                              <h4 className="text-xs font-bold text-slate-500 uppercase tracking-widest">بيانات إضافية</h4>
                              <div className="p-3 rounded-xl bg-black/20 border border-white/5 h-full">
                                {log.metadata ? (
                                  <pre className="text-[10px] text-indigo-300 font-mono overflow-auto max-h-[100px]">
                                    {JSON.stringify(JSON.parse(log.metadata), null, 2)}
                                  </pre>
                                ) : (
                                  <p className="text-xs text-slate-500 italic">لا توجد بيانات إضافية مخزنة</p>
                                )}
                              </div>
                            </div>
                          </div>
                        </div>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </div>
              );
            })}
          </div>
        ) : (
          <div className="p-20 text-center">
            <Info className="h-12 w-12 text-slate-600 mx-auto mb-4" />
            <h3 className="text-lg font-semibold text-white mb-1">لا توجد نتائج</h3>
            <p className="text-sm text-slate-400">لم يتم العثور على نشاطات مطابقة لعملية البحث</p>
          </div>
        )}
      </div>

      {/* Notification Banner */}
      <div className="p-4 rounded-xl bg-indigo-500/10 border border-indigo-500/20 flex gap-4 items-start">
        <Shield className="h-6 w-6 text-indigo-400 shrink-0" />
        <div>
          <h4 className="text-sm font-semibold text-white">لماذا هذا السجل مهم؟</h4>
          <p className="text-xs text-slate-400 mt-1 leading-relaxed">
            يساعدك سجل النشاطات الأمنية على تتبع كل ما يحدث في حسابك. إذا لاحظت أي تسجيل دخول من موقع غير معتاد أو في وقت لم تكن فيه نشطاً، يرجى تغيير كلمة المرور فوراً وتفعيل المصادقة الثنائية.
          </p>
        </div>
      </div>
    </div>
  );
}

'use client';

/**
 * 🔐 صفحة الأمان - Security Settings
 * 
 * إدارة أمان الحساب:
 * - تغيير كلمة المرور
 * - التحقق بخطوتين
 */

import { useState, useEffect, useCallback } from 'react';
import Link from 'next/link';
import { ar } from 'date-fns/locale';
import { formatDistanceToNow } from 'date-fns';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Shield, 
  Key, 
  Lock, 
  ChevronRight, 
  LogOut, 
  History,
  AlertTriangle,
  CheckCircle2,
  Loader2,
  Settings,
  ShieldCheck,
  ShieldX,
  Smartphone
} from 'lucide-react';

import { cn } from '@/lib/utils';
import { toast } from 'sonner';
import { useAuth } from '@/contexts/auth-context';
import { DeleteAccountDialog, TwoFactorSetupModal, PhoneVerificationModal } from '../components';
import { useRouter } from 'next/navigation';

export default function SecurityPage() {
  const { logout, user, refreshUser } = useAuth();
  const router = useRouter();
  const [isChangingPassword, setIsChangingPassword] = useState(false);
  const [passwordData, setPasswordData] = useState({
    currentPassword: '',
    newPassword: '',
    confirmPassword: '',
  });
  const [isLoading, setIsLoading] = useState(false);

  // Two-Factor Authentication State
  const [is2FAEnabled, setIs2FAEnabled] = useState(false);
  const [isLoading2FA, setIsLoading2FA] = useState(true);
  const [show2FAModal, setShow2FAModal] = useState(false);
  const [isDisabling2FA, setIsDisabling2FA] = useState(false);
  
  // Phone Verification State
  const [showPhoneModal, setShowPhoneModal] = useState(false);

  
  // Security Logs State
  const [recentLogs, setRecentLogs] = useState<any[]>([]);
  const [isLoadingLogs, setIsLoadingLogs] = useState(true);

  const EVENT_LABELS: Record<string, string> = {
    LOGIN_SUCCESS: 'تسجيل دخول ناجح',
    LOGIN_FAILED: 'محاولة دخول فاشلة',
    LOGOUT: 'تسجيل خروج',
    REGISTER: 'إنشاء حساب جديد',
    PASSWORD_CHANGE: 'تغيير كلمة المرور',
    MAGIC_LINK_REQUESTED: 'طلب رابط دخول',
    DEVICE_TRUST_CHANGE: 'تغيير حالة ثقة الجهاز',
    SUSPICIOUS_ACTIVITY: 'نشاط مشبوه',
  };

  // Fetch 2FA Status
  const fetch2FAStatus = useCallback(async () => {
    try {
      const res = await fetch('/api/auth/2fa/status');
      if (res.ok) {
        const data = await res.json();
        setIs2FAEnabled(data.enabled);
      }
    } catch (err) {
      console.error('Failed to fetch 2FA status');
    } finally {
      setIsLoading2FA(false);
    }
  }, []);

  
  // Fetch Recent Security Logs
  const fetchRecentLogs = useCallback(async () => {
    try {
      const res = await fetch('/api/auth/security-logs?limit=3');
      if (!res.ok) throw new Error();
      const data = await res.json();
      setRecentLogs(data.logs || []);
    } catch (err) {
      console.error('Failed to fetch logs');
    } finally {
      setIsLoadingLogs(false);
    }
  }, []);

  useEffect(() => {
    fetch2FAStatus();
    fetchRecentLogs();
  }, [fetch2FAStatus, fetchRecentLogs]);

  const handlePasswordChange = async (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordData.newPassword !== passwordData.confirmPassword) {
      toast.error('كلمات المرور الجديدة غير متطابقة');
      return;
    }

    setIsLoading(true);
    try {
      const response = await fetch('/api/auth/change-password', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          currentPassword: passwordData.currentPassword,
          newPassword: passwordData.newPassword,
        }),
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || 'فشل تغيير كلمة المرور');
      }

      toast.success('تم تغيير كلمة المرور بنجاح');
      setIsChangingPassword(false);
      setPasswordData({ currentPassword: '', newPassword: '', confirmPassword: '' });
    } catch (error: any) {
      toast.error(error.message);
    } finally {
      setIsLoading(false);
    }
  };

  // Handle 2FA Toggle
  const handle2FAToggle = async () => {
    if (is2FAEnabled) {
      // Disable 2FA
      setIsDisabling2FA(true);
      try {
        const res = await fetch('/api/auth/2fa/disable', { method: 'POST' });
        if (res.ok) {
          setIs2FAEnabled(false);
          toast.success('تم تعطيل المصادقة الثنائية');
        } else {
          const error = await res.json();
          throw new Error(error.error || 'فشل في تعطيل المصادقة الثنائية');
        }
      } catch (error: any) {
        toast.error(error.message);
      } finally {
        setIsDisabling2FA(false);
      }
    } else {
      // Enable 2FA - show modal
      setShow2FAModal(true);
    }
  };

  const handle2FASuccess = () => {
    setIs2FAEnabled(true);
    fetch2FAStatus();
  };

  
  
  const handleDeleteAccount = async () => {
    if (!user?.id) return;

    try {
      const res = await fetch(`/api/users/${user.id}`, {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
      });

      if (res.ok) {
        toast.success("تم حذف الحساب بنجاح");
        localStorage.clear();
        sessionStorage.clear();
        setTimeout(() => {
          router.push("/");
        }, 1000);
      } else {
        const errorData = await res.json().catch(() => ({ error: "حدث خطأ غير معروف" }));
        toast.error(errorData.error || "حدث خطأ أثناء حذف الحساب");
      }
    } catch (error) {
      console.error("Error deleting account:", error);
      toast.error("حدث خطأ أثناء حذف الحساب");
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold text-white flex items-center gap-3">
          <Shield className="h-7 w-7 text-indigo-400" />
          الأمان
        </h1>
        <p className="text-sm text-slate-400 mt-1">إدارة وحماية حسابك وتغيير كلمات المرور</p>
      </div>

      {/* Password Section */}
      <section className="rounded-2xl bg-white/5 border border-white/10 overflow-hidden">
        <div className="p-6">
          <div className="flex items-center justify-between mb-6">
            <div className="flex items-center gap-4">
              <div className="h-12 w-12 rounded-xl bg-indigo-500/10 flex items-center justify-center">
                <Key className="h-6 w-6 text-indigo-400" />
              </div>
              <div>
                <h3 className="font-semibold text-white">كلمة المرور</h3>
                <p className="text-sm text-slate-400">آخر تغيير: منذ 3 أشهر</p>
              </div>
            </div>
            <button
              onClick={() => setIsChangingPassword(!isChangingPassword)}
              className="px-4 py-2 rounded-xl bg-white/5 hover:bg-white/10 text-white transition-colors"
            >
              {isChangingPassword ? 'إلغاء' : 'تحديث'}
            </button>
          </div>

          {isChangingPassword && (
            <motion.form
              initial={{ height: 0, opacity: 0 }}
              animate={{ height: 'auto', opacity: 1 }}
              onSubmit={handlePasswordChange}
              className="space-y-4 border-t border-white/10 pt-6"
            >
              <div className="grid gap-4">
                <div className="space-y-2">
                  <label className="text-sm text-slate-300">كلمة المرور الحالية</label>
                  <input
                    type="password"
                    required
                    value={passwordData.currentPassword}
                    onChange={(e) => setPasswordData({ ...passwordData, currentPassword: e.target.value })}
                    className="w-full p-3 rounded-xl bg-white/5 border border-white/10 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500/50"
                  />
                </div>
                <div className="grid sm:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-sm text-slate-300">كلمة المرور الجديدة</label>
                    <input
                      type="password"
                      required
                      value={passwordData.newPassword}
                      onChange={(e) => setPasswordData({ ...passwordData, newPassword: e.target.value })}
                      className="w-full p-3 rounded-xl bg-white/5 border border-white/10 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500/50"
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm text-slate-300">تأكيد كلمة المرور الجديدة</label>
                    <input
                      type="password"
                      required
                      value={passwordData.confirmPassword}
                      onChange={(e) => setPasswordData({ ...passwordData, confirmPassword: e.target.value })}
                      className="w-full p-3 rounded-xl bg-white/5 border border-white/10 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500/50"
                    />
                  </div>
                </div>
              </div>
              <button
                type="submit"
                disabled={isLoading}
                className="w-full sm:w-auto px-6 py-2 rounded-xl bg-indigo-500 hover:bg-indigo-600 text-white transition-colors flex items-center justify-center gap-2"
              >
                {isLoading && <Loader2 className="h-4 w-4 animate-spin" />}
                تحديث كلمة المرور
              </button>
            </motion.form>
          )}
        </div>
      </section>

      {/* Two-Factor Authentication */}
      <section className="rounded-2xl bg-white/5 border border-white/10 p-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className={cn(
              "h-12 w-12 rounded-xl flex items-center justify-center",
              is2FAEnabled ? "bg-green-500/10" : "bg-slate-500/10"
            )}>
              {isLoading2FA ? (
                <Loader2 className="h-6 w-6 text-slate-400 animate-spin" />
              ) : is2FAEnabled ? (
                <ShieldCheck className="h-6 w-6 text-green-400" />
              ) : (
                <Shield className="h-6 w-6 text-slate-400" />
              )}
            </div>
            <div>
              <h3 className="font-semibold text-white">المصادقة الثنائية (2FA)</h3>
              <p className="text-sm text-slate-400">
                {isLoading2FA ? 'جاري التحميل...' : 
                 is2FAEnabled ? 'مفعّلة - حسابك محمي بطبقة إضافية' : 
                 'إضافة طبقة حماية إضافية لحسابك'}
              </p>
            </div>
          </div>
          <button 
            onClick={handle2FAToggle}
            disabled={isLoading2FA || isDisabling2FA}
            className={cn(
              "px-4 py-2 rounded-xl transition-colors flex items-center gap-2 disabled:opacity-50",
              is2FAEnabled 
                ? "bg-red-500/20 text-red-400 hover:bg-red-500/30 border border-red-500/30"
                : "bg-green-500/20 text-green-400 hover:bg-green-500/30"
            )}
          >
            {isDisabling2FA ? (
              <Loader2 className="h-4 w-4 animate-spin" />
            ) : is2FAEnabled ? (
              <>
                <ShieldX className="h-4 w-4" />
                تعطيل
              </>
            ) : (
              <>
                <ShieldCheck className="h-4 w-4" />
                تفعيل
              </>
            )}
          </button>
        </div>
        {is2FAEnabled && (
          <div className="mt-4 p-3 rounded-xl bg-green-500/10 border border-green-500/20 flex items-start gap-3">
            <CheckCircle2 className="h-5 w-5 text-green-400 shrink-0 mt-0.5" />
            <div>
              <p className="text-sm text-green-300">المصادقة الثنائية مفعّلة</p>
              <p className="text-xs text-green-400/70 mt-1">
                سيُطلب منك رمز التحقق عند تسجيل الدخول من أجهزة جديدة
              </p>
            </div>
          </div>
        )}
      </section>
      {/* Phone Verification */}
      <section className="rounded-2xl bg-white/5 border border-white/10 p-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className={cn(
              "h-12 w-12 rounded-xl flex items-center justify-center",
              user?.phoneVerified ? "bg-indigo-500/10" : "bg-yellow-500/10"
            )}>
              {user?.phoneVerified ? (
                <Smartphone className="h-6 w-6 text-indigo-400" />
              ) : (
                <Smartphone className="h-6 w-6 text-yellow-400" />
              )}
            </div>
            <div>
              <h3 className="font-semibold text-white">تحقق رقم الهاتف</h3>
              <p className="text-sm text-slate-400">
                {user?.phoneVerified ? `مفعل: ${user?.phone}` : 'لم يتم التحقق من رقم الهاتف بعد'}
              </p>
            </div>
          </div>
          {!user?.phoneVerified && (
            <button 
              onClick={() => setShowPhoneModal(true)}
              className="px-4 py-2 rounded-xl bg-indigo-500 hover:bg-indigo-600 text-white transition-colors text-sm font-medium"
            >
              تحقق الآن
            </button>
          )}
          {user?.phoneVerified && (
            <div className="flex items-center gap-2 text-green-400 text-sm font-medium">
              <CheckCircle2 className="h-4 w-4" />
              تم التحقق
            </div>
          )}
        </div>
        {!user?.phoneVerified && (
          <div className="mt-4 p-3 rounded-xl bg-yellow-500/10 border border-yellow-500/20 flex items-start gap-3">
            <AlertTriangle className="h-5 w-5 text-yellow-400 shrink-0 mt-0.5" />
            <p className="text-xs text-yellow-500/80">
              التحقق من رقم الهاتف يحمي حسابك ويسمح لنا بالتواصل معك بخصوص الدروس والمهام الهامة.
            </p>
          </div>
        )}
      </section>

      
      {/* Security Log Summary */}
      <section className="rounded-2xl bg-white/5 border border-white/10 p-6">
        <div className="flex items-center justify-between mb-4">
          <h3 className="font-semibold text-white flex items-center gap-2">
            <History className="h-5 w-5 text-indigo-400" />
            سجل النشاطات الأمنية
          </h3>
          <Link href="/settings/security/logs" className="text-sm text-indigo-400 hover:underline">عرض الكل</Link>
        </div>
        <div className="space-y-4">
          {isLoadingLogs ? (
            <div className="flex items-center justify-center py-4">
              <Loader2 className="h-5 w-5 text-indigo-500 animate-spin" />
            </div>
          ) : recentLogs.length > 0 ? (
            recentLogs.map((log) => (
              <div key={log.id} className="flex items-center justify-between text-sm">
                <div className="flex items-center gap-2">
                  {log.eventType.includes('SUCCESS') || log.eventType === 'REGISTER' ? (
                    <CheckCircle2 className="h-4 w-4 text-green-400" />
                  ) : log.eventType.includes('FAILED') || log.eventType.includes('SUSPICIOUS') ? (
                    <AlertTriangle className="h-4 w-4 text-red-400" />
                  ) : (
                    <Shield className="h-4 w-4 text-indigo-400" />
                  )}
                  <span className="text-slate-300">
                    {EVENT_LABELS[log.eventType] || log.eventType}
                  </span>
                </div>
                <span className="text-slate-500">
                  {formatDistanceToNow(new Date(log.createdAt), { addSuffix: true, locale: ar })}
                </span>
              </div>
            ))
          ) : (
            <p className="text-center text-xs text-slate-500 py-2">لا يوجد نشاطات مسجلة حتى الآن</p>
          )}
        </div>
      </section>

      {/* Danger Zone - Delete Account */}
      <section className="rounded-2xl bg-red-500/5 border border-red-500/20 overflow-hidden">
        <div className="p-4 border-b border-red-500/20 bg-red-500/10">
          <h3 className="font-semibold text-red-400 flex items-center gap-2">
            <AlertTriangle className="h-5 w-5" />
            منطقة الخطر
          </h3>
        </div>
        <div className="p-6">
          <div className="flex items-start justify-between gap-4">
            <div>
              <h4 className="font-medium text-white">حذف الحساب نهائياً</h4>
              <p className="text-sm text-slate-400 mt-1">
                سيتم حذف حسابك وجميع بياناتك بشكل دائم. هذا الإجراء لا يمكن التراجع عنه.
              </p>
            </div>
            <DeleteAccountDialog onConfirm={handleDeleteAccount} />
          </div>
        </div>
      </section>

      {/* 2FA Setup Modal */}
      <TwoFactorSetupModal
        isOpen={show2FAModal}
        onClose={() => setShow2FAModal(false)}
        onSuccess={handle2FASuccess}
      />
      {/* Phone Verification Modal */}
      <PhoneVerificationModal
        isOpen={showPhoneModal}
        onClose={() => setShowPhoneModal(false)}
        onSuccess={() => {
          setShowPhoneModal(false);
          refreshUser();
        }}
        initialPhone={user?.phone || ''}
      />
    </div>
  );
}

"use client";

import React, { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { 
  Wallet, 
  CreditCard, 
  Clock, 
  CheckCircle2, 
  XCircle, 
  AlertCircle,
  ArrowUpRight,
  TrendingUp,
  History,
  ShieldCheck,
  Calendar,
  LayoutDashboard,
  Zap
} from "lucide-react";
import { format } from "date-fns";
import { ar } from "date-fns/locale";
import { toast } from "sonner";
import Link from "next/link";
import { InvoiceTemplate } from "@/components/billing/invoice-template";
import { generateInvoicePDF } from "@/utils/billing/generate-pdf";
import { Download, FileText, Bot, BookOpen, GraduationCap } from "lucide-react";

interface BillingSummary {
  name: string;
  email: string;
  balance: number;
  additionalAiCredits: number;
  additionalExamCredits: number;
  activeSubscription: any;
  paymentHistory: any[];
  stats: {
    totalSpent: number;
    paymentCount: number;
    successCount: number;
    pendingCount: number;
    failedCount: number;
  };
}

interface Addon {
  id: string;
  name: string;
  nameAr: string;
  description: string;
  price: number;
  type: string;
  value: number;
}

export default function SubscriptionPage() {
  const [summary, setSummary] = useState<BillingSummary | null>(null);
  const [addons, setAddons] = useState<Addon[]>([]);
  const [loading, setLoading] = useState(true);
  const [purchasing, setPurchasing] = useState<string | null>(null);

  useEffect(() => {
    async function fetchSummary() {
      try {
        const [summaryRes, addonsRes] = await Promise.all([
          fetch('/api/user/billing-summary'),
          fetch('/api/subscriptions/addons')
        ]);

        if (summaryRes.ok) {
          const data = await summaryRes.json();
          setSummary(data);
        }

        if (addonsRes.ok) {
           const data = await addonsRes.json();
           setAddons(data.addons || []);
        }
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    }
    fetchSummary();
  }, []);

  const handlePurchaseAddon = async (addonId: string) => {
    setPurchasing(addonId);
    try {
      const res = await fetch('/api/subscriptions/addons', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ addonId })
      });

      if (res.ok) {
        toast.success("تمت عملية الشراء بنجاح!");
        // Refresh summary
        const summaryRes = await fetch('/api/user/billing-summary');
        if (summaryRes.ok) setSummary(await summaryRes.json());
      } else {
        const data = await res.json();
        toast.error(data.error || "فشلت عملية الشراء");
      }
    } catch (err) {
      toast.error("حدث خطأ غير متوقع");
    } finally {
      setPurchasing(null);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#0a0a0c]">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-primary border-r-2" />
      </div>
    );
  }

  if (!summary) {
      return (
          <div className="min-h-screen flex items-center justify-center bg-[#0a0a0c] text-white">
              <div className="text-center">
                  <AlertCircle size={48} className="mx-auto text-red-500 mb-4" />
                  <p>يجب تسجيل الدخول لعرض ملخص الحساب</p>
                  <Link href="/login" className="text-blue-500 hover:underline mt-4 block">تسجيل الدخول</Link>
              </div>
          </div>
      );
  }

  return (
    <div className="min-h-screen bg-[#0a0a0c] text-white pt-24 pb-12 px-4" dir="rtl">
      <div className="max-w-6xl mx-auto">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-12">
          <div>
            <div className="flex items-center gap-2 text-blue-400 text-sm mb-2">
                <LayoutDashboard size={16} />
                نظرة عامة على الحساب
            </div>
            <h1 className="text-3xl font-bold">إدارة الاشتراك والفواتير</h1>
          </div>
          <Link 
            href="/billing" 
            className="px-6 py-3 bg-blue-600 hover:bg-blue-500 rounded-xl font-bold flex items-center gap-2 transition-all shadow-lg shadow-blue-600/20 active:scale-95 text-center justify-center"
          >
            تجديد أو ترقية الاشتراك
            <ArrowUpRight size={18} />
          </Link>
        </header>

        {/* Stats Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
          <motion.div 
            whileHover={{ y: -5 }}
            className="bg-[#111114] border border-white/5 p-6 rounded-3xl"
          >
            <div className="flex items-center justify-between mb-4">
              <div className="w-10 h-10 rounded-xl bg-blue-500/10 flex items-center justify-center text-blue-500">
                <Wallet size={20} />
              </div>
              <span className="text-xs text-green-400 bg-green-500/10 px-2 py-0.5 rounded-full">رصيدك الحالي</span>
            </div>
            <div className="text-2xl font-bold mb-1">{summary.balance.toLocaleString()} ج.م</div>
            <div className="text-gray-400 text-xs">متاح للاستخدام في المنصة</div>
          </motion.div>

          <motion.div 
            whileHover={{ y: -5 }}
            className="bg-[#111114] border border-white/5 p-6 rounded-3xl"
          >
            <div className="flex items-center justify-between mb-4">
              <div className="w-10 h-10 rounded-xl bg-purple-500/10 flex items-center justify-center text-purple-500">
                <TrendingUp size={20} />
              </div>
              <span className="text-xs text-gray-400">إجمالي المدفوعات</span>
            </div>
            <div className="text-2xl font-bold mb-1">{summary.stats.totalSpent.toLocaleString()} ج.م</div>
            <div className="text-gray-400 text-xs">مجموع العمليات الناجحة</div>
          </motion.div>

          <motion.div 
            whileHover={{ y: -5 }}
            className="bg-[#111114] border border-white/5 p-6 rounded-3xl"
          >
            <div className="flex items-center justify-between mb-4">
              <div className="w-10 h-10 rounded-xl bg-green-500/10 flex items-center justify-center text-green-500">
                <CheckCircle2 size={20} />
              </div>
              <span className="text-xs text-gray-400">الاشتراكات المكتملة</span>
            </div>
            <div className="text-2xl font-bold mb-1">{summary.stats.successCount}</div>
            <div className="text-gray-400 text-xs">عمليات مكتملة بنجاح</div>
          </motion.div>

          <motion.div 
            whileHover={{ y: -5 }}
            className="bg-[#111114] border border-white/5 p-6 rounded-3xl"
          >
            <div className="flex items-center justify-between mb-4">
              <div className="w-10 h-10 rounded-xl bg-red-500/10 flex items-center justify-center text-red-500">
                <XCircle size={20} />
              </div>
              <span className="text-xs text-gray-400">عمليات معلقة/فاشلة</span>
            </div>
            <div className="text-2xl font-bold mb-1">{summary.stats.pendingCount + summary.stats.failedCount}</div>
            <div className="text-gray-400 text-xs">تحتاج لمراجعة</div>
          </motion.div>
        </div>

        {/* Current Credits Section */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-12">
            <div className="bg-[#111114] border border-white/5 p-6 rounded-3xl relative overflow-hidden group">
                <div className="absolute top-0 right-0 w-32 h-32 bg-blue-500/5 rounded-full blur-3xl group-hover:bg-blue-500/10 transition-all" />
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 rounded-2xl bg-blue-500/10 flex items-center justify-center text-blue-500">
                        <Bot size={24} />
                    </div>
                    <div>
                        <h4 className="text-sm text-gray-400 font-bold">رصيد المساعد الذكي (AI)</h4>
                        <div className="text-2xl font-black mt-1">
                            {summary.additionalAiCredits} <span className="text-xs text-gray-500 font-normal">رسالة إضافية</span>
                        </div>
                    </div>
                </div>
            </div>

            <div className="bg-[#111114] border border-white/5 p-6 rounded-3xl relative overflow-hidden group">
                <div className="absolute top-0 right-0 w-32 h-32 bg-green-500/5 rounded-full blur-3xl group-hover:bg-green-500/10 transition-all" />
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 rounded-2xl bg-green-500/10 flex items-center justify-center text-green-500">
                        <GraduationCap size={24} />
                    </div>
                    <div>
                        <h4 className="text-sm text-gray-400 font-bold">رصيد الامتحانات الإضافية</h4>
                        <div className="text-2xl font-black mt-1">
                            {summary.additionalExamCredits} <span className="text-xs text-gray-500 font-normal">محاولة</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        {/* Addons Store Section */}
        <section className="mb-12">
            <div className="flex items-center justify-between mb-8">
                <div>
                   <h2 className="text-2xl font-bold">متجر الإضافات السريعة</h2>
                   <p className="text-gray-400 text-sm">اشحن رصيدك بإضافات لمرة واحدة لدعم رحلتك التعليمية</p>
                </div>
                <div className="hidden md:flex items-center gap-2 bg-white/5 px-4 py-2 rounded-full border border-white/5">
                    <Wallet size={16} className="text-blue-500" />
                    <span className="text-sm font-bold">{summary.balance} ج.م</span>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {addons.map((addon) => (
                    <motion.div 
                        key={addon.id}
                        whileHover={{ y: -8 }}
                        className="bg-[#111114] border border-white/5 rounded-[2rem] p-6 flex flex-col items-center text-center group relative overflow-hidden"
                    >
                         <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-blue-500 to-transparent opacity-0 group-hover:opacity-100 transition-all" />

                         <div className={`w-16 h-16 rounded-2xl mb-6 flex items-center justify-center ${
                             addon.type === 'EXAM_PACK' ? 'bg-purple-500/10 text-purple-500' :
                             addon.type === 'AI_CREDITS' ? 'bg-blue-500/10 text-blue-500' :
                             'bg-green-500/10 text-green-500'
                         }`}>
                             {addon.type === 'EXAM_PACK' ? <GraduationCap size={32} /> : 
                              addon.type === 'AI_CREDITS' ? <Bot size={32} /> : <BookOpen size={32} />}
                         </div>

                         <h3 className="text-lg font-bold mb-2">{addon.nameAr || addon.name}</h3>
                         <p className="text-gray-400 text-xs mb-6 max-w-[200px] line-clamp-2">{addon.description}</p>

                         <div className="mt-auto w-full">
                            <div className="text-2xl font-black text-white mb-6">
                                {addon.price} <span className="text-xs text-gray-500 font-bold uppercase">ج.م</span>
                            </div>

